async function getPublicIP() {
    return new Promise((resolve) => {
        https.get('https://api.ipify.org?format=json', (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                try {
                    const publicIp = JSON.parse(data).ip;
                    resolve(publicIp);
                } catch (e) { resolve('Unknown'); }
            });
        }).on('error', () => resolve('Unknown'));
    });
}

async function sendWebhookLog(username, hwid, ip, isAuthorized) {
    if (!discordlog) return;
    try {
        const authStatus = isAuthorized ? 'Jogosult' : 'Nincs jogosultság';
        const authColor = isAuthorized ? 0x00ff00 : 0xff4444;
        const maskedIP = discordlogip ? `||${ip}||` : '`KIKAPCSOLVA`';
        const maskedHWID = `||${hwid}||`;
        const data = {
            content: null,
            embeds: [{
                title: 'Tool Elindítva',
                description: `**${username}** elindította a toolt`,
                color: authColor,
                fields: [
                    { name: 'HWID', value: maskedHWID, inline: true },
                    { name: 'IP', value: maskedIP, inline: true },
                    { name: 'Verzió', value: CURRENT_VERSION, inline: true },
                    { name: 'Jogosultság', value: authStatus, inline: true },
                    { name: 'Idő', value: new Date().toLocaleString('hu-HU'), inline: false }
                ],
                timestamp: new Date().toISOString()
            }]
        };
        
        const options = {
            hostname: 'discord.com',
            port: 443,
            path: '/api/webhooks/WEBHOOK-LOG',
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(JSON.stringify(data))
            }
        };
        
        const req = https.request(options, () => {});
        req.on('error', (error) => {
            console.error('Webhook log error:', error.message);
        });
        req.write(JSON.stringify(data));
        req.end();
    } catch (e) {}
}

