async function checkForUpdates() {
    return new Promise((resolve) => {
        try {
            const httpModule = UPDATE_CHECK_URL.startsWith('https') ? require('https') : require('http');
            const url = new URL(UPDATE_CHECK_URL);
            const options = {
                hostname: url.hostname,
                port: url.port || (url.protocol === 'https:' ? 443 : 80),
                path: url.pathname + url.search,
                method: 'GET',
                headers: {
                    'User-Agent': `Nutella-Toolkit/${CURRENT_VERSION}`,
                    'Accept': 'application/json'
                },
                timeout: 5000
            };

            const req = httpModule.request(options, (res) => {
                let data = '';
                res.on('data', (chunk) => data += chunk);
                res.on('end', () => {
                    try {
                        if (res.statusCode === 200) {
                            const versionData = JSON.parse(data);
                            const latestVersion = versionData.version;
                            const hasUpdate = compareVersions(CURRENT_VERSION, latestVersion) < 0;
                            
                            updateCheckResult = {
                                hasUpdate: hasUpdate,
                                currentVersion: CURRENT_VERSION,
                                latestVersion: latestVersion,
                                downloadUrl: 'https://ntk-x.eu/dashboard',
                                releaseNotes: 'Új frissítés érhető el az irányítópulton!',
                                forceUpdate: false
                            };
                            
                            resolve(updateCheckResult);
                        } else {
                            resolve({ hasUpdate: false, error: `HTTP ${res.statusCode}` });
                        }
                    } catch (e) {
                        resolve({ hasUpdate: false, error: 'Invalid JSON' });
                    }
                });
            });

            req.on('error', () => resolve({ hasUpdate: false, error: 'Network error' }));
            req.on('timeout', () => { req.destroy(); resolve({ hasUpdate: false, error: 'Timeout' }); });
            req.end();
        } catch (e) {
            resolve({ hasUpdate: false, error: e.message });
        }
    });
}

function compareVersions(v1, v2) {
    const parts1 = v1.split('.').map(Number);
    const parts2 = v2.split('.').map(Number);
    
    for (let i = 0; i < Math.max(parts1.length, parts2.length); i++) {
        const p1 = parts1[i] || 0;
        const p2 = parts2[i] || 0;
        if (p1 < p2) return -1;
        if (p1 > p2) return 1;
    }
    return 0;
}

async function safeShowSaveDialog(options) {
    try {
        const window = global.mainWindow && !global.mainWindow.isDestroyed() ? global.mainWindow : null;
        const result = await dialog.showSaveDialog(window, options);
        return result;
    } catch (error) {
        console.error('Dialog error:', error);
        try {
            const result = await dialog.showSaveDialog(options);
            return result;
        } catch (fallbackError) {
            console.error('Fallback dialog error:', fallbackError);
            return { canceled: true };
        }
    }
}

async function safeDeleteWithRetry(filePath, maxRetries = 3, delayMs = 1000) {
    if (!filePath) return;
    for (let i = 0; i < maxRetries; i++) {
        try {
            await fs.promises.unlink(filePath);
            return;
        } catch (error) {
            if (error.code === 'EBUSY' && i < maxRetries - 1) {
                await new Promise(r => setTimeout(r, delayMs));
            } else if (error.code !== 'ENOENT') {
                console.error(`Failed to delete ${filePath}:`, error.message);
            }
        }
    }
}

async function safeDeleteDirWithRetry(dirPath, maxRetries = 3, delayMs = 1000) {
    if (!dirPath) return;
    for (let i = 0; i < maxRetries; i++) {
        try {
            await fs.promises.rm(dirPath, { recursive: true, force: true });
            return;
        } catch (error) {
            if (error.code === 'EBUSY' && i < maxRetries - 1) {
                await new Promise(r => setTimeout(r, delayMs));
            } else if (error.code !== 'ENOENT') {
                console.error(`Failed to delete dir ${dirPath}:`, error.message);
            }
        }
    }
}

