ipcMain.on('fivem-server-lookup', async (event, input) => {
    try {
        let code = input.trim();
        let isIp = false;
        let targetUrl = '';

        if (code.match(/^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+(:[0-9]+)?$/)) {
            isIp = true;
            if (!code.includes(':')) code += ':30120';
            targetUrl = `http://${code}/`;
        } else {
            if (code.includes('cfx.re/join/')) {
                code = code.split('cfx.re/join/')[1].split('/')[0].split('?')[0];
            } else if (code.startsWith('http')) {
                const parts = code.split('/');
                code = parts[parts.length - 1].split('?')[0];
            }

            if (!code || code.length < 4) {
                event.reply('fivem-server-lookup-res', { success: false, error: 'Érvénytelen kód formátum!' });
                return;
            }
        }

        const fetchServerData = (url) => {
            if (!url.endsWith('/')) url += '/';
            const reqModule = url.startsWith('https') ? https : require('http');
            reqModule.get(`${url}info.json`, { timeout: 10000 }, (infoRes) => {
                let infoData = '';
                infoRes.on('data', chunk => infoData += chunk);
                infoRes.on('end', () => {
                    try {
                        const serverData = JSON.parse(infoData);
                        reqModule.get(`${url}players.json`, { timeout: 10000 }, (playersRes) => {
                            let playersData = '';
                            playersRes.on('data', chunk => playersData += chunk);
                            playersRes.on('end', () => {
                                try {
                                    const playersJson = JSON.parse(playersData);
                                    
                                    const ipWithPort = url.replace(/^https?:\/\//, '').replace(/\/$/, '');
                                    const ipParts = ipWithPort.split(':');
                                    const cleanIp = ipParts[0];
                                    const cleanPort = ipParts[1] ? parseInt(ipParts[1]) : 80;
                                    
                                    if (cleanIp && !cleanIp.includes('cfx.re')) {
                                        measurePing(cleanIp, cleanPort).then(serverPing => {
                                            event.reply('fivem-server-lookup-res', {
                                                success: true,
                                                ip: ipWithPort || 'Rejtett / CFX Proxy',
                                                ping: serverPing,
                                                players: playersJson || [],
                                                maxPlayers: serverData.vars?.sv_maxClients || '?',
                                                resources: serverData.resources || [],
                                                name: serverData.vars?.sv_projectName || serverData.vars?.sv_hostname || 'Ismeretlen',
                                                isAdmin: (serverData.resources || []).includes('txAdmin')
                                            });
                                        });
                                    } else {
                                        event.reply('fivem-server-lookup-res', {
                                            success: true,
                                            ip: ipWithPort || 'Rejtett / CFX Proxy',
                                            ping: 'N/A',
                                            players: playersJson || [],
                                            maxPlayers: serverData.vars?.sv_maxClients || '?',
                                            resources: serverData.resources || [],
                                            name: serverData.vars?.sv_projectName || serverData.vars?.sv_hostname || 'Ismeretlen',
                                            isAdmin: (serverData.resources || []).includes('txAdmin')
                                        });
                                    }
                                } catch(e) {
                                    event.reply('fivem-server-lookup-res', { success: false, error: 'Hibás players.json válasz.' });
                                }
                            });
                        }).on('error', () => {
                            event.reply('fivem-server-lookup-res', { success: false, error: 'Hálózati hiba a players.json lekérésnél.' });
                        });
                    } catch(e) {
                        event.reply('fivem-server-lookup-res', { success: false, error: 'Hibás info.json válasz.' });
                    }
                });
            }).on('error', () => {
                event.reply('fivem-server-lookup-res', { success: false, error: 'Hálózati hiba a szerver adatok lekérésénél.' });
            });
        };

        if (isIp) {
            fetchServerData(targetUrl);
        } else {
            const options = {
                method: 'GET',
                headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36' }
            };
            const resolveReq = https.request(`https://cfx.re/join/${code}`, options, (res) => {
                let resolvedUrl = res.headers['x-citizenfx-url'] || res.headers['location'];
                if (!resolvedUrl) {
                    event.reply('fivem-server-lookup-res', { success: false, error: 'Érvénytelen szerver kód vagy proxyzott cím!' });
                    return;
                }
                fetchServerData(resolvedUrl);
            });
            
            resolveReq.on('error', (err) => {
                event.reply('fivem-server-lookup-res', { success: false, error: 'Hálózati hiba a kód feloldásánál.' });
            });
            resolveReq.end();
        }

    } catch (err) {
        event.reply('fivem-server-lookup-res', { success: false, error: err.message });
    }
});

ipcMain.on('get-server-ping-only', (event, ip) => {
    const { exec } = require('child_process');
    exec(`ping -n 1 ${ip}`, (error, stdout) => {
        if (!error) {
            const match = stdout.match(/time[=<](\d+)ms/);
            if (match) {
                event.reply('get-server-ping-only-res', { ping: match[1] + 'ms' });
                return;
            }
        }
        event.reply('get-server-ping-only-res', { ping: 'N/A' });
    });
});

