function initDiscordBot() {
    if (discordInitPromise) return discordInitPromise;
    
    discordInitPromise = new Promise((resolve) => {
        if (discordClient && discordClient.readyAt) {
            return resolve(discordClient);
        }
        
        if (!discordClient) {
            discordClient = new Client({
                intents: [
                    GatewayIntentBits.Guilds,
                    GatewayIntentBits.GuildMessages
                ]
            });

            discordClient.once('clientReady', async () => {
                loadLastIdeaData();
                
                loadDiscordMessageHistory('hu');
                loadDiscordMessageHistory('eng');
                
                await registerSlashCommands();
                await loadStatusData();
                resolve(discordClient);
            });

            discordClient.on('messageCreate', async (message) => {
                if (message.author.bot) return;
                
                const channelId = message.channel.id;
                const timestamp = new Date().toLocaleString('hu-HU');
                const hwid = generateHWID();
                const username = await getUsernameForHWID(hwid);
                
                if (channelId === DISCORD_CONFIG.channels.hu) {
                    if (mainWin) {
                        mainWin.webContents.send('new-discord-message', { lang: 'hu', message: message.content, timestamp: timestamp, name: username });
                    }
                } else if (channelId === DISCORD_CONFIG.channels.eng) {
                    if (mainWin) {
                        mainWin.webContents.send('new-discord-message', { lang: 'eng', message: message.content, timestamp: timestamp, name: username });
                    }
                }
            });

            discordClient.on('interactionCreate', async (interaction) => {
                if (!interaction.isChatInputCommand()) return;

                if (interaction.commandName === 'status-add') {
                    await handleStatusAdd(interaction);
                }
            });

            discordClient.login(DISCORD_CONFIG.token).catch(err => {
                console.error('Discord login error:', err);
                discordInitPromise = null;
                resolve(null);
            });
        } else {
            discordClient.once('clientReady', () => resolve(discordClient));
        }
    });
    
    return discordInitPromise;
}

