ipcMain.on('send-idea-message', async (event, data) => {
    await initDiscordBot();
    if (!discordClient || !discordClient.isReady()) return;

    try {
        const hwid = generateHWID();
        
        const username = await getUsernameForHWID(hwid);
        const channelId = '--ID--';
        
        const channel = await discordClient.channels.fetch(channelId);

        if (channel && channel.isTextBased && channel.isTextBased()) {
            const hours24 = 24 * 60 * 60 * 1000;
            const now = Date.now();

            let messages;
            try {
                messages = await Promise.race([
                    channel.messages.fetch({ limit: 50 }),
                    new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout')), 10000))
                ]);
            } catch (fetchErr) {
                messages = new Map();
            }
            
            let lastSentTime = 0;
            let foundMessageCount = 0;

            for (const msg of messages.values()) {
                if (msg.embeds && msg.embeds.length > 0) {
                    const embed = msg.embeds[0];
                    if (embed.fields) {
                        const hwidField = embed.fields.find(f => f.name === 'HWID');
                        if (hwidField && hwidField.value === hwid) {
                            foundMessageCount++;
                            const msgTime = msg.createdTimestamp;
                            if (msgTime > lastSentTime) {
                                lastSentTime = msgTime;
                            }
                        }
                    }
                }
            }

            if (now - lastSentTime < hours24 && lastSentTime > 0) {
                const timeRemaining = hours24 - (now - lastSentTime);
                const hoursRemaining = Math.floor(timeRemaining / (60 * 60 * 1000));
                const minutesRemaining = Math.floor((timeRemaining % (60 * 60 * 1000)) / (60 * 1000));
                const secondsRemaining = Math.floor((timeRemaining % (60 * 1000)) / 1000);

                const nextAvailableTime = lastSentTime + hours24;
                
                event.reply('idea-message-error', {
                    error: 'cooldown',
                    remainingMs: timeRemaining,
                    nextAvailableTime: nextAvailableTime
                });
                return;
            }
            
            const { EmbedBuilder } = require('discord.js');
            const embed = new EmbedBuilder()
                .setTitle('Új ötlet érkezett!')
                .setDescription(data.message)
                .addFields(
                    { name: 'HWID', value: hwid, inline: true },
                    { name: 'Username', value: username, inline: true }
                )
                .setColor(0xffd700)
                .setTimestamp();

            await channel.send({ embeds: [embed] });

            const nextAvailableTime = Date.now() + hours24;

            event.reply('idea-message-sent', { success: true, nextAvailableTime: nextAvailableTime });
        } else {
            event.reply('idea-message-error', { error: 'channel_error', message: 'Channel not found or not text-based' });
        }
    } catch (e) {
        event.reply('idea-message-error', { error: 'send_failed', message: 'Hiba történt az ötlet küldése közben: ' + e.message });
    }
});

async function checkPythonInstalled() {
    return new Promise((resolve) => {
        exec('python --version', (error, stdout, stderr) => {
            if (!error) {
                resolve(true);
                return;
            }
            
            exec('python3 --version', (error2, stdout2, stderr2) => {
                if (!error2) {
                    resolve(true);
                    return;
                }
                resolve(false);
            });
        });
    });
}

async function installPython(progressCallback) {
    return new Promise((resolve, reject) => {
        const platform = os.platform();
        
        if (platform === 'win32') {
            const pythonUrl = 'https://www.python.org/ftp/python/3.11.9/python-3.11.9-amd64.exe';
            const installerPath = path.join(os.tmpdir(), 'python-installer.exe');
            
            progressCallback('Python letöltése...');
            
            const file = fs.createWriteStream(installerPath);
            https.get(pythonUrl, (response) => {
                response.pipe(file);
                
                file.on('finish', () => {
                    file.close();
                    progressCallback('Python telepítése...');
                    
                    const installCommand = `"${installerPath}" /quiet InstallAllUsers=0 PrependPath=1 Include_test=0`;
                    exec(installCommand, (error, stdout, stderr) => {
                        fs.unlink(installerPath, () => {});
                        
                        if (error) {
                            reject(new Error(`Python telepítési hiba: ${error.message}`));
                        } else {
                            progressCallback('Python telepítése befejezve');
                            resolve();
                        }
                    });
                });
            }).on('error', (err) => {
                fs.unlink(installerPath, () => {});
                reject(new Error(`Python letöltési hiba: ${err.message}`));
            });
        } else {
            reject(new Error('Automatikus Python telepítés csak Windows-on támogatott'));
        }
    });
}

async function ensurePython(progressCallback) {
    const isInstalled = await checkPythonInstalled();
    
    if (!isInstalled) {
        await installPython(progressCallback);
        if (os.platform() === 'win32') {
            await new Promise((resolve) => {
                const { exec } = require('child_process');
                exec(`powershell -command "[Environment]::GetEnvironmentVariable('PATH', 'User') + ';' + [Environment]::GetEnvironmentVariable('PATH', 'Machine')"`, (err, stdout) => {
                    if (!err && stdout) process.env.PATH = stdout.trim();
                    resolve();
                });
            });
        }
        await new Promise(resolve => setTimeout(resolve, 2000));
    }
    
    return true;
}

async function getRoleIconAsBase64(guildId, iconHash) {
    if (!iconHash) return null;
    return new Promise((
        
    ) => {
        const possibleUrls = [
            `https://cdn.discordapp.com/role-icons/${iconHash}.png`,
            `https://cdn.discordapp.com/role-icons/${guildId}/${iconHash}.png`,
            `https://cdn.discordapp.com/icons/${guildId}/${iconHash}.png`
        ];
        
        let urlIndex = 0;
        
        const tryNextUrl = () => {
            if (urlIndex >= possibleUrls.length) {
                ('Failed to download role icon from all URLs');
                resolve(null);
                return;
            }
            
            const iconUrl = possibleUrls[urlIndex];
            const https = require('https');
            
            const req = https.get(iconUrl, (res) => {
                if (res.statusCode !== 200) {
                    (`Failed to download role icon from ${iconUrl}: HTTP ${res.statusCode}`);
                    urlIndex++;
                    tryNextUrl();
                    return;
                }
                
                const chunks = [];
                res.on('data', (chunk) => chunks.push(chunk));
                res.on('end', () => {
                    const buffer = Buffer.concat(chunks);
                    const base64 = `data:image/png;base64,${buffer.toString('base64')}`;
                    resolve(base64);
                });
            });
            
            req.on('error', (error) => {
                ('Error fetching role icon:', error);
                urlIndex++;
                tryNextUrl();
            });
            
            req.setTimeout(5000, () => {
                req.destroy();
                urlIndex++;
                tryNextUrl();
            });
        };
        
        tryNextUrl();
    });
}

