ipcMain.on('send-webhook', (event, url, message, index) => {
    try {
        const https = require('https');
        const { URL } = require('url');
        
        const payload = {
            content: message,
            username: 'Nutella Toolkit Spammer',
            avatar_url: 'https://r2.fivemanage.com/lWG0eICrT7bNyEqeNajIS/dafult.png'
        };
        
        
        const urlObj = new URL(url);
        const postData = JSON.stringify(payload);
        
        const options = {
            hostname: urlObj.hostname,
            port: urlObj.port || 443,
            path: urlObj.pathname + urlObj.search,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(postData)
            }
        };
        
        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => {
                data += chunk;
            });
            res.on('end', () => {
                if (res.statusCode >= 200 && res.statusCode < 300) {
                    event.reply('webhook-response', { index, success: true, status: res.statusCode, message: message });
                } else if (res.statusCode === 429) {
                    event.reply('webhook-response', { index, success: false, status: res.statusCode, errorType: 'rate_limit', message: message });
                } else if (res.statusCode === 404) {
                    event.reply('webhook-response', { index, success: false, status: res.statusCode, errorType: 'not_found', message: message, error: 'Webhook not found (deleted or invalid)' });
                } else if (res.statusCode === 401 || res.statusCode === 403) {
                    event.reply('webhook-response', { index, success: false, status: res.statusCode, errorType: 'unauthorized', message: message, error: 'Invalid webhook token' });
                } else {
                    event.reply('webhook-response', { index, success: false, status: res.statusCode, errorType: 'other', message: message, error: `HTTP ${res.statusCode}` });
                }
            });
        });
        
        req.on('error', (error) => {
            event.reply('webhook-response', { index, success: false, error: error.message, message: message });
        });
        
        req.write(postData);
        req.end();
        
    } catch (error) {
        event.reply('webhook-response', { index, success: false, error: error.message, message: message });
    }
});

