ipcMain.on('get-bot-token-info', async (event, token) => {
    try {
        const https = require('https');
        
        const botInfoOptions = {
            hostname: 'discord.com',
            port: 443,
            path: '/api/v10/users/@me',
            method: 'GET',
            headers: {
                'Authorization': 'Bot ' + token,
                'Content-Type': 'application/json'
            }
        };
        
        const botInfoReq = https.request(botInfoOptions, (botRes) => {
            let botData = '';
            botRes.on('data', (chunk) => {
                botData += chunk;
            });
            botRes.on('end', () => {
                if (botRes.statusCode === 200) {
                    try {
                        const botInfo = JSON.parse(botData);

                        const guildsOptions = {
                            hostname: 'discord.com',
                            port: 443,
                            path: '/api/v10/users/@me/guilds',
                            method: 'GET',
                            headers: {
                                'Authorization': 'Bot ' + token,
                                'Content-Type': 'application/json'
                            }
                        };
                        
                        const guildsReq = https.request(guildsOptions, (guildsRes) => {
                            let guildsData = '';
                            guildsRes.on('data', (chunk) => {
                                guildsData += chunk;
                            });
                            guildsRes.on('end', () => {
                                if (guildsRes.statusCode === 200) {
                                    try {
                                        const guilds = JSON.parse(guildsData);
                                        
                                        event.reply('bot-token-info-res', { 
                                            success: true, 
                                            info: {
                                                id: botInfo.id,
                                                username: botInfo.username,
                                                discriminator: botInfo.discriminator,
                                                avatar: botInfo.avatar,
                                                bot: botInfo.bot,
                                                email: botInfo.email || 'N/A',
                                                verified: botInfo.verified || false,
                                                guilds: guilds.map(guild => ({
                                                    id: guild.id,
                                                    name: guild.name,
                                                    icon: guild.icon,
                                                    owner: guild.owner,
                                                    permissions: guild.permissions,
                                                    features: guild.features || []
                                                }))
                                            }
                                        });
                                    } catch (e) {
                                        event.reply('bot-token-info-res', { success: false, error: 'Invalid JSON response for guilds' });
                                    }
                                } else {
                                    event.reply('bot-token-info-res', { 
                                        success: true, 
                                        info: {
                                            id: botInfo.id,
                                            username: botInfo.username,
                                            discriminator: botInfo.discriminator,
                                            avatar: botInfo.avatar,
                                            bot: botInfo.bot,
                                            email: botInfo.email || 'N/A',
                                            verified: botInfo.verified || false,
                                            guilds: []
                                        }
                                    });
                                }
                            });
                        });
                        
                        guildsReq.on('error', (error) => {
                            event.reply('bot-token-info-res', { 
                                success: true, 
                                info: {
                                    id: botInfo.id,
                                    username: botInfo.username,
                                    discriminator: botInfo.discriminator,
                                    avatar: botInfo.avatar,
                                    bot: botInfo.bot,
                                    email: botInfo.email || 'N/A',
                                    verified: botInfo.verified || false,
                                    guilds: []
                                }
                            });
                        });
                        
                        guildsReq.end();
                        
                    } catch (e) {
                        event.reply('bot-token-info-res', { success: false, error: 'Invalid JSON response for bot info' });
                    }
                } else {
                    event.reply('bot-token-info-res', { success: false, status: botRes.statusCode, error: 'Invalid token or unauthorized' });
                }
            });
        });
        
        botInfoReq.on('error', (error) => {
            event.reply('bot-token-info-res', { success: false, error: error.message });
        });
        
        botInfoReq.end();
        
    } catch (error) {
        event.reply('bot-token-info-res', { success: false, error: error.message });
    }
});

