ipcMain.on('clone-server', async (event, token, sourceGuildId, targetGuildId) => {
    try {
        const https = require('https');
        

        serverCloningActive = true;
        activeTimeouts = [];
        
        const hwid = generateHWID();
        const userLanguage = getLanguageForHWID(hwid) || 'hu';
        const locale = userLanguage === 'hu' ? 'hu-HU' : 'en-US';
        
        const startMsg = userLanguage === 'hu' ? '=== SZERVER KLÓNOZÁS INDÍTÁSA ===' : '=== SERVER CLONING STARTED ===';
        const fetchMsg = userLanguage === 'hu' ? 'Forrás szerver adatainak lekérdezése...' : 'Fetching source server data...';
        
        event.reply('server-clone-res', { success: true, message: startMsg });
        event.reply('server-clone-res', { success: true, message: fetchMsg });
        

        const sourceOptions = {
            hostname: 'discord.com',
            path: `/api/v10/guilds/${sourceGuildId}?with_counts=true`,
            method: 'GET',
            headers: {
                'Authorization': token,
                'Content-Type': 'application/json'
            }
        };
        
        const sourceReq = https.request(sourceOptions, (sourceRes) => {
            let sourceData = '';
            
            sourceRes.on('data', (chunk) => {
                sourceData += chunk;
            });
            
            sourceRes.on('end', () => {
                if (sourceRes.statusCode === 200) {
                    try {
                        const sourceGuild = JSON.parse(sourceData);
                        
                        const sourceInfoMsg = userLanguage === 'hu' ? 
                            `Forrás szerver: ${sourceGuild.name} (${sourceGuild.approximate_member_count || 'N/A'} tag)` :
                            `Source server: ${sourceGuild.name} (${sourceGuild.approximate_member_count || 'N/A'} members)`;
                        
                        event.reply('server-clone-res', { 
                            success: true, 
                            message: sourceInfoMsg
                        });
                        
                        const wipeMsg = userLanguage === 'hu' ? 'Cél szerver teljes törlése...' : 'Wiping target server completely...';
                        event.reply('server-clone-res', { success: true, message: wipeMsg });
                        wipeAndRebuildServer(token, sourceGuild, targetGuildId, event, userLanguage);
                        
                    } catch (e) {
                        event.reply('server-clone-res', { success: false, error: 'Failed to parse source server data' });
                    }
                } else {
                    let errorMsg = `Failed to fetch source server: ${sourceRes.statusCode}`;
                    if (sourceRes.statusCode === 401) {
                        errorMsg = `Hiba: Érvénytelen user token! (401)`;
                    } else if (sourceRes.statusCode === 403) {
                        errorMsg = userLanguage === 'hu' ? 
                            'Hiba: Nincs hozzáférésed a forrás szerverhez! (403)' :
                            'Error: No access to source server! (403)';
                    } else if (sourceRes.statusCode === 404) {
                        errorMsg = userLanguage === 'hu' ? 
                            'Hiba: A forrás szerver nem található! (404)' :
                            'Error: Source server not found! (404)';
                    }
                    event.reply('server-clone-res', { success: false, error: errorMsg });
                }
            });
        });
        
        sourceReq.on('error', (error) => {
            event.reply('server-clone-res', { success: false, error: error.message });
        });
        
        sourceReq.end();
    } catch (error) {
        event.reply('server-clone-res', { success: false, error: error.message });
    }
});

