let activeTimeouts = [];

ipcMain.on('stop-clone-server', (event) => {
    serverCloningActive = false;
    activeTimeouts.forEach(timeoutId => clearTimeout(timeoutId));
    activeTimeouts = [];
    event.reply('server-clone-res', { 
        success: true, 
        message: 'Klónozás leállítva felhasználó által!' 
    });
});

function wipeAndRebuildServer(token, sourceGuild, targetGuildId, event, userLanguage = 'hu') {
    const https = require('https');
    
    event.reply('server-clone-res', { 
        success: true, 
        message: userLanguage === 'hu' ? 
            '🗑️ 1. LÉPÉS: Minden törlése a cél szerverről...' : 
            '🗑️ STEP 1: Deleting everything from target server...'
    });

    const deleteAllChannels = () => {
        return new Promise((resolve) => {
            const channelOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/channels`,
                method: 'GET',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };

            const channelReq = https.request(channelOptions, (channelRes) => {
                let channelData = '';
                channelRes.on('data', chunk => channelData += chunk);
                channelRes.on('end', () => {
                    if (channelRes.statusCode === 200) {
                        try {
                            const channels = JSON.parse(channelData);
                            
                            if (channels.length === 0) {
                                event.reply('server-clone-res', { 
                                    success: true, 
                                    message: userLanguage === 'hu' ? 'ℹ️ Nincsenek csatornák' : 'ℹ️ No channels to delete'
                                });
                                resolve();
                                return;
                            }

                            let deletedCount = 0;
                            let failedCount = 0;
                            
                            channels.forEach((channel, index) => {
                                setTimeout(() => {
                                    const deleteOptions = {
                                        hostname: 'discord.com',
                                        path: `/api/v10/channels/${channel.id}`,
                                        method: 'DELETE',
                                        headers: {
                                            'Authorization': token,
                                            'Content-Type': 'application/json'
                                        }
                                    };

                                    const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                        if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                            deletedCount++;
                                        } else {
                                            failedCount++;
                                        }
                                        
                                        if (deletedCount + failedCount === channels.length) {
                                            const msg = userLanguage === 'hu' ? 
                                                `✓ ${deletedCount} csatorna törölve${failedCount > 0 ? ` (${failedCount} hiba)` : ''}` : 
                                                `✓ ${deletedCount} channels deleted${failedCount > 0 ? ` (${failedCount} failed)` : ''}`;
                                            event.reply('server-clone-res', { success: true, message: msg });
                                            resolve();
                                        }
                                    });

                                    deleteReq.on('error', () => {
                                        failedCount++;
                                        if (deletedCount + failedCount === channels.length) {
                                            resolve();
                                        }
                                    });
                                    deleteReq.end();
                                }, index * 100);
                            });
                        } catch (e) {
                            resolve();
                        }
                    } else {
                        resolve();
                    }
                });
            });
            
            channelReq.on('error', () => resolve());
            channelReq.end();
        });
    };

    const deleteAllRoles = () => {
        return new Promise((resolve) => {
            const roleOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/roles`,
                method: 'GET',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };

            const roleReq = https.request(roleOptions, (roleRes) => {
                let roleData = '';
                roleRes.on('data', chunk => roleData += chunk);
                roleRes.on('end', () => {
                    if (roleRes.statusCode === 200) {
                        try {
                            const roles = JSON.parse(roleData);
                            const deletableRoles = roles.filter(r => r.name !== '@everyone' && !r.managed);
                            
                            if (deletableRoles.length === 0) {
                                event.reply('server-clone-res', { 
                                    success: true, 
                                    message: userLanguage === 'hu' ? 'ℹ️ Nincsenek törölhető rangok' : 'ℹ️ No deletable roles'
                                });
                                resolve();
                                return;
                            }

                            let deletedCount = 0;
                            let failedCount = 0;
                            
                            deletableRoles.forEach((role, index) => {
                                setTimeout(() => {
                                    const deleteOptions = {
                                        hostname: 'discord.com',
                                        path: `/api/v10/guilds/${targetGuildId}/roles/${role.id}`,
                                        method: 'DELETE',
                                        headers: {
                                            'Authorization': token,
                                            'Content-Type': 'application/json'
                                        }
                                    };

                                    const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                        if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                            deletedCount++;
                                        } else {
                                            failedCount++;
                                        }
                                        
                                        if (deletedCount + failedCount === deletableRoles.length) {
                                            const msg = userLanguage === 'hu' ? 
                                                `✓ ${deletedCount} rang törölve${failedCount > 0 ? ` (${failedCount} hiba)` : ''}` : 
                                                `✓ ${deletedCount} roles deleted${failedCount > 0 ? ` (${failedCount} failed)` : ''}`;
                                            event.reply('server-clone-res', { success: true, message: msg });
                                            resolve();
                                        }
                                    });

                                    deleteReq.on('error', () => {
                                        failedCount++;
                                        if (deletedCount + failedCount === deletableRoles.length) {
                                            resolve();
                                        }
                                    });
                                    deleteReq.end();
                                }, index * 100);
                            });
                        } catch (e) {
                            resolve();
                        }
                    } else {
                        resolve();
                    }
                });
            });
            
            roleReq.on('error', () => resolve());
            roleReq.end();
        });
    };

    deleteAllChannels()
        .then(() => deleteAllRoles())
        .then(() => {
            event.reply('server-clone-res', { 
                success: true, 
                message: userLanguage === 'hu' ? 
                    '✅ Törlés kész! Párhuzamos klónozás indul...' : 
                    '✅ Deletion complete! Starting parallel clone...'
            });
            
            startParallelClone(token, sourceGuild, targetGuildId, event, userLanguage);
        });
}

function cloneServerIcon(token, iconHash, sourceGuildId, targetGuildId, event, callback) {
    const https = require('https');
    
    event.reply('server-clone-res', { success: true, message: 'Logó klónozása...' });
    
    const iconUrl = `https://cdn.discordapp.com/icons/${sourceGuildId}/${iconHash}.png`;
    
    event.reply('server-clone-res', { 
        success: true, 
        message: `Debug: Logó URL`,
        url: iconUrl,
        isClickable: true
    });
    
    const iconReq = https.request(iconUrl, (iconRes) => {
        let iconData = [];
        iconRes.on('data', chunk => iconData.push(chunk));
        iconRes.on('end', () => {
            const iconBuffer = Buffer.concat(iconData);
            
            const iconBase64 = `data:image/png;base64,${iconBuffer.toString('base64')}`;
            
            const updateOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}`,
                method: 'PATCH',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const updateReq = https.request(updateOptions, (updateRes) => {
                let updateData = '';
                updateRes.on('data', chunk => updateData += chunk);
                updateRes.on('end', () => {
                    if (updateRes.statusCode === 200) {
                        event.reply('server-clone-res', { success: true, message: '✓ Logó sikeresen klónozva' });
                        if (callback) callback();
                    } else {
                        event.reply('server-clone-res', { success: false, message: `Failed to update icon: ${updateRes.statusCode}` });
                        if (callback) callback();
                    }
                });
            });
            
            updateReq.on('error', (error) => {
                event.reply('server-clone-res', { success: false, message: `Error updating icon: ${error.message}` });
                if (callback) callback();
            });
            
            const iconUpdateData = {
                icon: iconBase64
            };
            
            updateReq.write(JSON.stringify(iconUpdateData));
            updateReq.end();
        });
    });
    
    iconReq.on('error', (error) => {
        event.reply('server-clone-res', { success: false, message: `Error downloading icon: ${error.message}` });
        if (callback) callback();
    });
    
    iconReq.end();
}

function sendParallelLog(event, column, message, isError = false) {
    const columnEmoji = {
        roles: '',
        categories: '',
        channels: ''
    };

    const shortPrefix = {
        roles: 'R:',
        categories: 'K:',
        channels: 'C:'
    };
    
    event.reply('server-clone-parallel', {
        success: !isError,
        column: column,
        emoji: columnEmoji[column],
        shortPrefix: shortPrefix[column],
        message: message,
        isError: isError,
        timestamp: Date.now()
    });
}

function updateEveryonePermissions(token, targetGuildId, event, userLanguage) {
    const https = require('https');
    
    if (!parallelCloneState.everyonePermissions) {
        return;
    }
    
    const getOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${targetGuildId}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const getReq = https.request(getOptions, (getRes) => {
        let getData = '';
        getRes.on('data', chunk => getData += chunk);
        getRes.on('end', () => {
            if (getRes.statusCode === 200) {
                try {
                    const roles = JSON.parse(getData);
                    const everyoneRole = roles.find(r => r.name === '@everyone');
                    
                    if (everyoneRole) {
                        const updateOptions = {
                            hostname: 'discord.com',
                            path: `/api/v10/guilds/${targetGuildId}/roles/${everyoneRole.id}`,
                            method: 'PATCH',
                            headers: {
                                'Authorization': token,
                                'Content-Type': 'application/json'
                            }
                        };
                        
                        const updateReq = https.request(updateOptions, (updateRes) => {
                            let updateData = '';
                            updateRes.on('data', chunk => updateData += chunk);
                            updateRes.on('end', () => {
                                if (updateRes.statusCode === 200) {
                                    sendParallelLog(event, 'roles', '✓ @everyone rang jogosultságok frissítve');
                                } else {
                                    sendParallelLog(event, 'roles', `✗ @everyone rang frissítése sikertelen (HTTP ${updateRes.statusCode})`, true);
                                    if (updateData) {
                                        sendParallelLog(event, 'roles', `Hiba részletek: ${updateData}`, true);
                                    }
                                }
                            });
                        });
                        
                        updateReq.on('error', (error) => {
                            sendParallelLog(event, 'roles', `✗ @everyone rang frissítési hiba: ${error.message}`, true);
                        });
                        
                        const roleData = {
                            permissions: parallelCloneState.everyonePermissions
                        };
                        
                        updateReq.write(JSON.stringify(roleData));
                        updateReq.end();
                    } else {
                        sendParallelLog(event, 'roles', '✗ @everyone rang nem található', true);
                    }
                } catch (e) {
                    sendParallelLog(event, 'roles', `✗ Hiba a rangok feldolgozásakor: ${e.message}`, true);
                }
            } else {
                sendParallelLog(event, 'roles', `✗ Rangok lekérése sikertelen (HTTP ${getRes.statusCode})`, true);
            }
        });
    });
    
    getReq.on('error', (error) => {
        sendParallelLog(event, 'roles', `✗ Rangok lekérési hiba: ${error.message}`, true);
    });
    
    getReq.end();
}

function checkAllParallelComplete(event, targetGuildId, token, userLanguage) {
    const state = parallelCloneState;
    
    if (state.categories.completed && state.waitingChannels && state.waitingChannels.length > 0) {
        sendParallelLog(event, 'channels', ` Várakozó csatornák feldolgozása: ${state.waitingChannels.length} darab`);
        
        const waitingChannels = state.waitingChannels;
        state.waitingChannels = [];
        
        waitingChannels.forEach((waitingChannel, index) => {
            setTimeout(() => {
                waitingChannel.createChannel();
            }, index * 1000);
        });
        
        return;
    }
    
    if (state.roles.completed && state.categories.completed && state.channels.completed && !state.allCompleted) {
        state.allCompleted = true;
        
        sendParallelLog(event, 'roles', `━━━━━━━━━━━━━━━━━━━━━━━`);
        sendParallelLog(event, 'categories', `━━━━━━━━━━━━━━━━━━━━━━━`);
        sendParallelLog(event, 'channels', `━━━━━━━━━━━━━━━━━━━━━━━`);
        
        sendParallelLog(event, 'roles', `${state.roles.created}/${state.roles.total} kész` + (state.roles.failed > 0 ? ` | ${state.roles.failed} hiba` : ''));
        sendParallelLog(event, 'categories', `${state.categories.created}/${state.categories.total} kész` + (state.categories.failed > 0 ? ` | ${state.categories.failed} hiba` : ''));
        sendParallelLog(event, 'channels', `${state.channels.created}/${state.channels.total} kész` + (state.channels.failed > 0 ? ` | ${state.channels.failed} hiba` : ''));
        
        if (state.roles.failed > 0 || state.categories.failed > 0 || state.channels.failed > 0) {
            sendParallelLog(event, 'roles', `⚠️ HIBÁK:`);
            sendParallelLog(event, 'categories', `⚠️ HIBÁK:`);
            sendParallelLog(event, 'channels', `⚠️ HIBÁK:`);
            
            if (state.roles.failed > 0) {
                sendParallelLog(event, 'roles', `• ${state.roles.failed} rang nem sikerült`, true);
            }
            if (state.categories.failed > 0) {
                sendParallelLog(event, 'categories', `• ${state.categories.failed} kategória nem sikerült`, true);
            }
            if (state.channels.failed > 0) {
                sendParallelLog(event, 'channels', `• ${state.channels.failed} csatorna nem sikerült`, true);
            }
        }
        
        event.reply('server-clone-res', {
            success: true,
            message: `=== PÁRHUZAMOS KLÓNOZÁS KÉSZ ===\nRangok: ${state.roles.created}/${state.roles.total}${state.roles.failed > 0 ? ' (' + state.roles.failed + ' hiba)' : ''}\nKategóriák: ${state.categories.created}/${state.categories.total}${state.categories.failed > 0 ? ' (' + state.categories.failed + ' hiba)' : ''}\nCsatornák: ${state.channels.created}/${state.channels.total}${state.channels.failed > 0 ? ' (' + state.channels.failed + ' hiba)' : ''}`
        });
        
        event.reply('scroll-logs-to-bottom', {});
        
        setupParallelPermissions(token, targetGuildId, event, userLanguage);
        
        updateEveryonePermissions(token, targetGuildId, event, userLanguage);
    }
}

function startParallelClone(token, sourceGuild, targetGuildId, event, userLanguage = 'hu') {
    const https = require('https');
    
    parallelCloneState = {
        roles: { created: 0, total: 0, failed: 0, completed: false },
        categories: { created: 0, total: 0, failed: 0, completed: false },
        channels: { created: 0, total: 0, failed: 0, completed: false },
        roleMap: new Map(),
        categoryMap: {},
        channelMap: {},
        waitingChannels: [],
        permissionMaps: {
            categories: new Map(),
            channels: new Map()
        },
        allCompleted: false,
        sourceGuild: sourceGuild
    };
    
    event.reply('server-clone-res', {
        success: true,
        message: '🚀 PÁRHUZAMOS KLÓNOZÁS INDÍTÁSA - 3 oszlopos megjelenítés'
    });
    
    sendParallelLog(event, 'roles', '📥 Rangok betöltése...');
    sendParallelLog(event, 'categories', '📥 Kategóriák betöltése...');
    sendParallelLog(event, 'channels', '📥 Csatornák betöltése...');
    
    const rolesOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${sourceGuild.id}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const rolesReq = https.request(rolesOptions, (rolesRes) => {
        let rolesData = '';
        rolesRes.on('data', chunk => rolesData += chunk);
        rolesRes.on('end', () => {
            if (rolesRes.statusCode === 200) {
                try {
                    const allRoles = JSON.parse(rolesData);
                    const sourceRoles = allRoles
                        .filter(r => r.name !== '@everyone')
                        .sort((a, b) => b.position - a.position);

                    const everyoneRole = allRoles.find(r => r.name === '@everyone');
                    if (everyoneRole) {
                        parallelCloneState.everyonePermissions = everyoneRole.permissions;
                        sendParallelLog(event, 'roles', '📋 @everyone rang jogosultságok mentve');
                    }
                    
                    parallelCloneState.roles.total = sourceRoles.length;

                    const channelsOptions = {
                        hostname: 'discord.com',
                        path: `/api/v10/guilds/${sourceGuild.id}/channels`,
                        method: 'GET',
                        headers: {
                            'Authorization': token,
                            'Content-Type': 'application/json'
                        }
                    };
                    
                    const channelsReq = https.request(channelsOptions, (channelsRes) => {
                        let channelsData = '';
                        channelsRes.on('data', chunk => channelsData += chunk);
                        channelsRes.on('end', () => {
                            if (channelsRes.statusCode === 200) {
                                try {
                                    const sourceChannels = JSON.parse(channelsData);
                                    
                                    const categories = sourceChannels.filter(c => c.type === 4);
                                    const textChannels = sourceChannels.filter(c => c.type === 0);
                                    const voiceChannels = sourceChannels.filter(c => c.type === 2);
                                    
                                    parallelCloneState.categories.total = categories.length;
                                    parallelCloneState.channels.total = textChannels.length + voiceChannels.length;
                                    
                                    sendParallelLog(event, 'roles', `📊 ${sourceRoles.length} rang találva`);
                                    sendParallelLog(event, 'categories', `📊 ${categories.length} kategória találva`);
                                    sendParallelLog(event, 'channels', `📊 ${textChannels.length + voiceChannels.length} csatorna találva (${textChannels.length} szöveg, ${voiceChannels.length} hang)`);
                                    
                                    event.reply('server-clone-res', {
                                        success: true,
                                        message: '⚡ Párhuzamos létrehozás indul...'
                                    });
                                    
                                    deleteExistingRoles(token, targetGuildId, event, userLanguage, () => {
                                        deleteExistingChannels(token, targetGuildId, event, userLanguage, () => {
                                            createRolesParallel(token, sourceRoles, targetGuildId, event, userLanguage, sourceGuild, () => {
                                                parallelCloneState.roles.completed = true;
                                                checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                                            });
                                            createCategoriesParallel(token, categories, targetGuildId, event, userLanguage, null, sourceGuild);

                                            const startChannelsDelay = categories.length > 0 ? Math.min(3 * 3000, 6000) : 1000;
                                            setTimeout(() => {
                                                createChannelsParallel(token, textChannels, voiceChannels, targetGuildId, event, userLanguage, sourceGuild);
                                            }, startChannelsDelay);
                                        });
                                    });
                                    
                                } catch (e) {
                                    sendParallelLog(event, 'channels', `❌ Hiba: ${e.message}`, true);
                                }
                            } else {
                                sendParallelLog(event, 'channels', `❌ API hiba: ${channelsRes.statusCode}`, true);
                            }
                        });
                    });
                    
                    channelsReq.on('error', (error) => {
                        sendParallelLog(event, 'channels', `❌ Hálózati hiba: ${error.message}`, true);
                    });
                    
                    channelsReq.end();
                    
                } catch (e) {
                    sendParallelLog(event, 'roles', `❌ Hiba: ${e.message}`, true);
                }
            } else {
                sendParallelLog(event, 'roles', `❌ API hiba: ${rolesRes.statusCode}`, true);
            }
        });
    });
    
    rolesReq.on('error', (error) => {
        sendParallelLog(event, 'roles', `❌ Hálózati hiba: ${error.message}`, true);
    });
    
    rolesReq.end();
}

function createRolesParallel(token, sourceRoles, targetGuildId, event, userLanguage, sourceGuild, callback = null) {
    const https = require('https');
    
    sendParallelLog(event, 'roles', '🚀 Rangok létrehozása elindult...');
    
    ('=== ORIGINAL ROLES ===');
    sourceRoles.forEach((role, index) => {
        (`${index}: ${role.name} (position: ${role.position}, managed: ${role.managed})`);
    });
    ('=== END ORIGINAL ROLES ===');
    
    if (sourceRoles.length === 0) {
        parallelCloneState.roles.completed = true;
        sendParallelLog(event, 'roles', '✅ Nincsenek rangok');
        checkAllParallelComplete(event, targetGuildId, token, userLanguage);
        return;
    }
    
    let createdCount = 0;
    let failedCount = 0;
    
    const filteredRoles = sourceRoles.filter(role => {
        if (role.name === '@everyone') {
            (`Filtered out role: @everyone`);
            return false;
        }
        
        (`Role included: ${role.name} (position: ${role.position}, managed: ${role.managed})`);
        return true;
    });
    
    sendParallelLog(event, 'roles', `📊 ${filteredRoles.length} rang létrehozható (eredeti: ${sourceRoles.length})`);

    filteredRoles.forEach((role, index) => {
        const timeoutId = setTimeout(() => {
            if (!serverCloningActive) {
                sendParallelLog(event, 'roles', '⛔ Leállítva', true);
                return;
            }
            
            const createOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/roles`,
                method: 'POST',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };

            let roleName = role.name
                .replace(/<a?:[^>]+:\d+>/g, '')
                .replace(/[<>"\/\\|?*\x00-\x1f]/g, '')
                .trim();


            if (!roleName || roleName.length === 0) {
                roleName = 'Role ' + (index + 1);
                sendParallelLog(event, 'roles', ` egyedi ikonok eltávolítva -> "${roleName}"`);
            } else if (roleName !== role.name.trim()) {
                sendParallelLog(event, 'roles', ` egyedi ikonok eltávolítva: "${role.name.trim()}" -> "${roleName}"`);
            }

            if (role.unicode_emoji) {
                sendParallelLog(event, 'roles', ` emoji ikonnal`);
            }
            if (role.icon) {
                sendParallelLog(event, 'roles', ` egyedi ikonnal`);
            }

            const createRoleWithIcon = async (roleData) => {

                if (role.icon && !role.icon.startsWith('data:')) {
                    sendParallelLog(event, 'roles', ` ikon kihagyva (API korlátozás)`);
                    roleData.icon = null;
                }
                
                return roleData;
            };

            createRoleWithIcon({
                name: roleName,
                permissions: role.permissions.toString(),
                color: role.color,
                hoist: role.hoist,
                icon: null,
                unicode_emoji: role.unicode_emoji || null,
                mentionable: role.mentionable
            }).then(finalRoleData => {
                ('=== ROLE CREATE DATA ===');
                ('Role name:', finalRoleData.name);
                ('Role data:', JSON.stringify(finalRoleData, null, 2));
                ('=== END ROLE CREATE DATA ===');
                
                const createReq = https.request(createOptions, (createRes) => {
                    let responseData = '';
                    createRes.on('data', chunk => responseData += chunk);
                    createRes.on('end', () => {
                        if (createRes.statusCode === 200) {
                            try {
                                const newRole = JSON.parse(responseData);
                                parallelCloneState.roleMap.set(role.id, newRole.id);
                                if (!parallelCloneState.rolePositions) {
                                    parallelCloneState.rolePositions = new Map();
                                }
                                parallelCloneState.rolePositions.set(newRole.id, role.position);
                                
                                sendParallelLog(event, 'roles', `✅ ${roleName}`);
                                createdCount++;
                                parallelCloneState.roles.created = createdCount;
                                
                                if (createdCount + failedCount === filteredRoles.length) {
                                    sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
                                    if (callback) callback();
                                }
                            } catch (e) {
                                sendParallelLog(event, 'roles', `✗ ${roleName} (Érvénytelen válasz: ${e.message})`, true);
                                failedCount++;
                                parallelCloneState.roles.failed = failedCount;
                                
                                if (createdCount + failedCount === filteredRoles.length) {
                                    sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
                                    if (callback) callback();
                                }
                            }
                        } else {
                            sendParallelLog(event, 'roles', `✗ ${roleName} (HTTP ${createRes.statusCode})`, true);
                            failedCount++;
                            parallelCloneState.roles.failed = failedCount;
                            
                            if (createdCount + failedCount === filteredRoles.length) {
                                sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
                                if (callback) callback();
                            }
                        }
                    });
                });
                
                createReq.on('error', (error) => {
                    sendParallelLog(event, 'roles', `✗ ${roleName} (Hálózati hiba)`, true);
                    failedCount++;
                    parallelCloneState.roles.failed = failedCount;
                    
                    if (createdCount + failedCount === filteredRoles.length) {
                        sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
                        if (callback) callback();
                    }
                });
                
                createReq.write(JSON.stringify(finalRoleData));
                createReq.end();
            }).catch(error => {
                sendParallelLog(event, 'roles', `✗ ${roleName} (Ikon hiba: ${error.message})`, true);
                failedCount++;
                parallelCloneState.roles.failed = failedCount;
                
                if (createdCount + failedCount === filteredRoles.length) {
                    sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
                    if (callback) callback();
                }
            });
        }, index * 1000);
        
        activeTimeouts.push(timeoutId);
    });

    if (createdCount + failedCount === filteredRoles.length) {
        parallelCloneState.roles.completed = true;
        sendParallelLog(event, 'roles', `🎉 ${createdCount}/${filteredRoles.length} rang létrehozva (${failedCount} hiba)`);
        checkAllParallelComplete(event, targetGuildId, token, userLanguage);
    }
}

function deleteExistingChannels(token, guildId, event, userLanguage, callback) {
    const https = require('https');
    
    sendParallelLog(event, 'channels', '🗑️ Meglévő csatornák és kategóriák törlése...');

    const channelsOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${guildId}/channels`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const channelsReq = https.request(channelsOptions, (channelsRes) => {
        let channelsData = '';
        channelsRes.on('data', chunk => channelsData += chunk);
        channelsRes.on('end', () => {
            if (channelsRes.statusCode === 200) {
                try {
                    const channels = JSON.parse(channelsData);
                    
                    if (channels.length === 0) {
                        sendParallelLog(event, 'channels', '✅ Nincsenek törlendő csatornák');
                        if (callback) callback();
                        return;
                    }
                    
                    sendParallelLog(event, 'channels', `📊 ${channels.length} csatorna törlése...`);
                    
                    let deletedCount = 0;
                    let failedCount = 0;
                    
                    channels.forEach((channel, index) => {
                        const timeoutId = setTimeout(() => {
                            if (!serverCloningActive) {
                                sendParallelLog(event, 'channels', '⛔ Csatorna törlés leállítva', true);
                                return;
                            }
                            
                            const deleteOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/channels/${channel.id}`,
                                method: 'DELETE',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                    deletedCount++;
                                    const channelType = channel.type === 4 ? '' : (channel.type === 0 ? '' : '');
                                    sendParallelLog(event, 'channels', ` ${channelType} ${channel.name}`);
                                } else {
                                    failedCount++;
                                    sendParallelLog(event, 'channels', `✗ ${channel.name} (HTTP ${deleteRes.statusCode})`, true);
                                }
                                
                                if (deletedCount + failedCount === channels.length) {
                                    sendParallelLog(event, 'channels', ` ${deletedCount}/${channels.length} csatorna törölve`);
                                    if (callback) callback();
                                }
                            });
                            
                            deleteReq.on('error', () => {
                                failedCount++;
                                sendParallelLog(event, 'channels', `✗ ${channel.name} (Hálózati hiba)`, true);
                                
                                if (deletedCount + failedCount === channels.length) {
                                    sendParallelLog(event, 'channels', ` ${deletedCount}/${channels.length} csatorna törölve (${failedCount} hiba)`);
                                    if (callback) callback();
                                }
                            });
                            
                            deleteReq.end();
                        }, index * 500);
                        
                        activeTimeouts.push(timeoutId);
                    });
                    
                } catch (e) {
                    sendParallelLog(event, 'channels', `❌ Hiba a csatornák törlésekor: ${e.message}`, true);
                    if (callback) callback();
                }
            } else {
                sendParallelLog(event, 'channels', `❌ API hiba: ${channelsRes.statusCode}`, true);
                if (callback) callback();
            }
        });
    });
    
    channelsReq.on('error', (error) => {
        sendParallelLog(event, 'channels', `❌ Hálózati hiba: ${error.message}`, true);
        if (callback) callback();
    });
    
    channelsReq.end();
}

function deleteExistingRoles(token, guildId, event, userLanguage, callback) {
    const https = require('https');
    
    sendParallelLog(event, 'roles', '🗑️ Meglévő rangok törlése...');

    const rolesOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${guildId}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const rolesReq = https.request(rolesOptions, (rolesRes) => {
        let rolesData = '';
        rolesRes.on('data', chunk => rolesData += chunk);
        rolesRes.on('end', () => {
            if (rolesRes.statusCode === 200) {
                try {
                    const roles = JSON.parse(rolesData);
                    
                    const rolesToDelete = roles.filter(role => {
                        if (role.position === -1 || role.name === '@everyone' || role.managed === true && role.tags && role.tags.bot_id === null) {
                            return false;
                        }
                        return true;
                    });
                    
                    if (rolesToDelete.length === 0) {
                        sendParallelLog(event, 'roles', '✅ Nincsenek törlendő rangok');
                        if (callback) callback();
                        return;
                    }
                    
                    sendParallelLog(event, 'roles', `📊 ${rolesToDelete.length} rang törlése...`);
                    
                    let deletedCount = 0;
                    let failedCount = 0;
                    
                    rolesToDelete.forEach((role, index) => {
                        const timeoutId = setTimeout(() => {
                            if (!serverCloningActive) {
                                sendParallelLog(event, 'roles', '⛔ Rang törlés leállítva', true);
                                return;
                            }
                            
                            const deleteOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${guildId}/roles/${role.id}`,
                                method: 'DELETE',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                    deletedCount++;
                                    sendParallelLog(event, 'roles', `🗑️ ${role.name}`);
                                } else {
                                    failedCount++;
                                    sendParallelLog(event, 'roles', `✗ ${role.name} (HTTP ${deleteRes.statusCode})`, true);
                                }
                                
                                if (deletedCount + failedCount === rolesToDelete.length) {
                                    sendParallelLog(event, 'roles', `🎉 ${deletedCount}/${rolesToDelete.length} rang törölve`);
                                    if (callback) callback();
                                }
                            });
                            
                            deleteReq.on('error', () => {
                                failedCount++;
                                sendParallelLog(event, 'roles', `✗ ${role.name} (Hálózati hiba)`, true);
                                
                                if (deletedCount + failedCount === rolesToDelete.length) {
                                    sendParallelLog(event, 'roles', `🎉 ${deletedCount}/${rolesToDelete.length} rang törölve (${failedCount} hiba)`);
                                    if (callback) callback();
                                }
                            });
                            
                            deleteReq.end();
                        }, index * 1000);
                        
                        activeTimeouts.push(timeoutId);
                    });
                    
                } catch (e) {
                    sendParallelLog(event, 'roles', `❌ Hiba a rangok törlésekor: ${e.message}`, true);
                    if (callback) callback();
                }
            } else {
                sendParallelLog(event, 'roles', `❌ API hiba: ${rolesRes.statusCode}`, true);
                if (callback) callback();
            }
        });
    });
    
    rolesReq.on('error', (error) => {
        sendParallelLog(event, 'roles', `❌ Hálózati hiba: ${error.message}`, true);
        if (callback) callback();
    });
    
    rolesReq.end();
}

function createCategoriesParallel(token, categories, targetGuildId, event, userLanguage, callback, sourceGuild) {
    const https = require('https');
    
    const translations = {
        hu: {
            categories: {
            }
        },
        en: {
            categories: {
            }
        }
    };
    
    sendParallelLog(event, 'categories', '🚀 Kategóriák létrehozása elindult...');
    
    if (categories.length === 0) {
        parallelCloneState.categories.completed = true;
        sendParallelLog(event, 'categories', '✅ Nincsenek kategóriák');
        checkAllParallelComplete(event, targetGuildId, token, userLanguage);
        if (callback) callback();
        return;
    }
    
    let createdCount = 0;
    let failedCount = 0;
    
    const sortedCategories = categories.sort((a, b) => a.position - b.position);
    
    sortedCategories.forEach((category, index) => {
        const timeoutId = setTimeout(() => {
            if (!serverCloningActive) {
                sendParallelLog(event, 'categories', '⛔ Leállítva', true);
                return;
            }
            
            const createOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/channels`,
                method: 'POST',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };

            let mappedPermissions = [];
            if (category.permission_overwrites && category.permission_overwrites.length > 0) {
                mappedPermissions = category.permission_overwrites.map(perm => {
                    if (perm.type === 0) {
                        if (perm.id === sourceGuild.id) {
                            return {
                                id: targetGuildId,
                                type: perm.type,
                                allow: perm.allow,
                                deny: perm.deny
                            };
                        }
                        const targetRoleId = parallelCloneState.roleMap.get(perm.id);
                        if (targetRoleId) {
                            return {
                                id: targetRoleId,
                                type: perm.type,
                                allow: perm.allow,
                                deny: perm.deny
                            };
                        }
                    } else if (perm.type === 1) {
                        return {
                            id: perm.id,
                            type: perm.type,
                            allow: perm.allow,
                            deny: perm.deny
                        };
                    }
                    return null;
                }).filter(p => p !== null);
            }

            let categoryName = category.name
                .replace(/[<>"\/\\|?*\x00-\x1f]/g, '')
                .replace(/[^\p{L}\p{N}\p{M}\s\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff\u0100-\u017f\u00c0-\u00ff]/gu, '')
                .trim();
            
            if (!categoryName || categoryName.length === 0) {
                categoryName = 'Kategória ' + (index + 1);
                sendParallelLog(event, 'categories', ` kategória név tisztítva -> "${categoryName}"`);
            } else if (categoryName !== category.name.trim()) {
                sendParallelLog(event, 'categories', ` kategória név tisztítva: "${category.name.trim()}" -> "${categoryName}"`);
            }
            
            if (translations[userLanguage] && translations[userLanguage].categories && translations[userLanguage].categories[category.name]) {
                categoryName = translations[userLanguage].categories[category.name];
            }
            
            const categoryData = {
                name: categoryName,
                type: 4,
                position: category.position,
                permission_overwrites: mappedPermissions
            };
            
            const createReq = https.request(createOptions, (createRes) => {
                let responseData = '';
                createRes.on('data', chunk => responseData += chunk);
                createRes.on('end', () => {
                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                        try {
                            const newCategory = JSON.parse(responseData);
                            parallelCloneState.categoryMap[category.id] = newCategory.id;
                            createdCount++;
                            parallelCloneState.categories.created = createdCount;
                            
                            sendParallelLog(event, 'categories', categoryName);
                        } catch (e) {
                            failedCount++;
                            parallelCloneState.categories.failed = failedCount;
                            sendParallelLog(event, 'categories', `✗ ${categoryName}`, true);
                        }
                    } else {
                        failedCount++;
                        parallelCloneState.categories.failed = failedCount;
                        sendParallelLog(event, 'categories', `✗ ${categoryName} (HTTP ${createRes.statusCode})`, true);
                    }
                    
                    if (createdCount + failedCount === sortedCategories.length) {
                        parallelCloneState.categories.completed = true;
                        sendParallelLog(event, 'categories', `🎉 ${createdCount}/${sortedCategories.length} kategória kész`);
                        checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                        if (callback) callback();
                    }
                });
            });
            
            createReq.on('error', (error) => {
                failedCount++;
                parallelCloneState.categories.failed = failedCount;
                sendParallelLog(event, 'categories', `✗ ${categoryName} (Hálózati hiba)`, true);
                
                if (createdCount + failedCount === sortedCategories.length) {
                    parallelCloneState.categories.completed = true;
                    checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                }
            });
            
            createReq.write(JSON.stringify(categoryData));
            createReq.end();
            
        }, index * 3000);
        
        activeTimeouts.push(timeoutId);
    });
}

function createChannelsParallel(token, textChannels, voiceChannels, targetGuildId, event, userLanguage, sourceGuild) {
    const https = require('https');
    
    sendParallelLog(event, 'channels', '🚀 Csatornák létrehozása elindult...');
    
    const allChannels = [...textChannels, ...voiceChannels];
    
    if (allChannels.length === 0) {
        parallelCloneState.channels.completed = true;
        sendParallelLog(event, 'channels', '✅ Nincsenek csatornák');
        checkAllParallelComplete(event, targetGuildId, token, userLanguage);
        return;
    }
    
    let createdCount = 0;
    let failedCount = 0;
    
    const sortedChannels = allChannels.sort((a, b) => a.position - b.position);
    
    sortedChannels.forEach((channel, index) => {
        const createChannelWithRetry = (retryCount = 0) => {
            if (!serverCloningActive) {
                sendParallelLog(event, 'channels', 'Leállítva', true);
                return;
            }

            let parentId = null;
            if (channel.parent_id && parallelCloneState.categoryMap[channel.parent_id]) {
                parentId = parallelCloneState.categoryMap[channel.parent_id];
                sendParallelLog(event, 'channels', `${channel.name} -> ${parentId} kategóriába`);
            } else if (channel.parent_id) {
                sendParallelLog(event, 'channels', `+ ${channel.name} várakozik a kategóriára`);
                parallelCloneState.waitingChannels.push({
                    channel: channel,
                    createChannel: createChannelWithRetry
                });
                return;
            }
            
            let mappedPermissions = [];
            if (channel.permission_overwrites && channel.permission_overwrites.length > 0) {
                mappedPermissions = channel.permission_overwrites.map(perm => {
                    if (perm.type === 0) {
                        if (perm.id === sourceGuild.id) {
                            return {
                                id: targetGuildId,
                                type: perm.type,
                                allow: perm.allow,
                                deny: perm.deny
                            };
                        }
                        const targetRoleId = parallelCloneState.roleMap.get(perm.id);
                        if (targetRoleId) {
                            return {
                                id: targetRoleId,
                                type: perm.type,
                                allow: perm.allow,
                                deny: perm.deny
                            };
                        }
                    } else if (perm.type === 1) {
                        return {
                            id: perm.id,
                            type: perm.type,
                            allow: perm.allow,
                            deny: perm.deny
                        };
                    }
                    return null;
                }).filter(p => p !== null);
            }
            
            const createOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/channels`,
                method: 'POST',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const channelData = {
                name: channel.name,
                type: channel.type,
                position: channel.position,
                parent_id: parentId,
                topic: channel.topic,
                nsfw: channel.nsfw,
                bitrate: channel.bitrate,
                user_limit: channel.user_limit,
                rate_limit_per_user: channel.rate_limit_per_user,
                permission_overwrites: mappedPermissions
            };
            
            const createReq = https.request(createOptions, (createRes) => {
                let responseData = '';
                createRes.on('data', chunk => responseData += chunk);
                createRes.on('end', () => {
                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                        try {
                            const newChannel = JSON.parse(responseData);
                            parallelCloneState.channelMap[channel.id] = newChannel.id;
                            createdCount++;
                            parallelCloneState.channels.created = createdCount;
                            
                            sendParallelLog(event, 'channels', channel.name);
                            
                            if (createdCount + failedCount === allChannels.length) {
                                parallelCloneState.channels.completed = true;
                                sendParallelLog(event, 'channels', `🎉 ${createdCount}/${allChannels.length} csatorna kész`);
                                checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                            }
                        } catch (e) {
                            failedCount++;
                            parallelCloneState.channels.failed = failedCount;
                            sendParallelLog(event, 'channels', `✗ ${channel.name}`, true);
                            
                            if (createdCount + failedCount === allChannels.length) {
                                parallelCloneState.channels.completed = true;
                                sendParallelLog(event, 'channels', `🎉 ${createdCount}/${allChannels.length} csatorna kész (${failedCount} hiba)`);
                                checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                            }
                        }
                    } else {
                        failedCount++;
                        parallelCloneState.channels.failed = failedCount;
                        sendParallelLog(event, 'channels', `✗ ${channel.name} (HTTP ${createRes.statusCode})`, true);
                        
                        if (createdCount + failedCount === allChannels.length) {
                            parallelCloneState.channels.completed = true;
                            sendParallelLog(event, 'channels', `🎉 ${createdCount}/${allChannels.length} csatorna kész (${failedCount} hiba)`);
                            checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                        }
                    }    
                });
            });
            
            createReq.on('error', (error) => {
                failedCount++;
                parallelCloneState.channels.failed = failedCount;
                sendParallelLog(event, 'channels', `✗ ${channel.name} (Hálózati hiba)`, true);
                
                if (createdCount + failedCount === allChannels.length) {
                    parallelCloneState.channels.completed = true;
                    checkAllParallelComplete(event, targetGuildId, token, userLanguage);
                }
            });
            
            createReq.write(JSON.stringify(channelData));
            createReq.end();
        };
        
        const timeoutId = setTimeout(() => createChannelWithRetry(), index * 2000);
        
        activeTimeouts.push(timeoutId);
    });
}

function setupParallelPermissions(token, targetGuildId, event, userLanguage) {
    const https = require('https');
    
    event.reply('server-clone-res', {
        success: true,
        message: '🔐 Jogosultságok beállítása a párhuzamosan létrehozott elemekhez...'
    });
    
    const sourceGuild = parallelCloneState.sourceGuild;
    if (sourceGuild && sourceGuild.name) {
        sendParallelLog(event, 'roles', `📝 Szerver név: ${sourceGuild.name}`);
        
        const nameUpdateOptions = {
            hostname: 'discord.com',
            path: `/api/v10/guilds/${targetGuildId}`,
            method: 'PATCH',
            headers: {
                'Authorization': token,
                'Content-Type': 'application/json'
            }
        };
        
        const nameReq = https.request(nameUpdateOptions, (nameRes) => {
            if (nameRes.statusCode === 200) {
                sendParallelLog(event, 'roles', '✅ Szerver név beállítva');
            }
        });
        
        nameReq.on('error', () => {});
        nameReq.write(JSON.stringify({ name: sourceGuild.name }));
        nameReq.end();
    }
    
    const channelsOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${targetGuildId}/channels`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const channelsReq = https.request(channelsOptions, (channelsRes) => {
        let channelsData = '';
        channelsRes.on('data', chunk => channelsData += chunk);
        channelsRes.on('end', () => {
            if (channelsRes.statusCode === 200) {
                try {
                    const channels = JSON.parse(channelsData);
                    
                    sendParallelLog(event, 'roles', '🔐 Jogosultságok ellenőrzése...');
                    
                    sendParallelLog(event, 'roles', '✅ Csatorna jogosultságok már beállítva');
                    sendParallelLog(event, 'categories', '✅ Kategória jogosultságok már beállítva');
                    sendParallelLog(event, 'channels', '✅ Csatorna jogosultságok már beállítva');
                    
                    const sourceGuild = parallelCloneState.sourceGuild;
                    if (sourceGuild && sourceGuild.icon) {
                        sendParallelLog(event, 'roles', '🎨 Szerver ikon klónozása...');
                        cloneServerIcon(token, sourceGuild.icon, sourceGuild.id, targetGuildId, event, () => {
                            sendParallelLog(event, 'roles', '✅ Ikon klónozva');
                        });
                    }
                    
                    event.reply('server-clone-res', {
                        success: true,
                        message: '✅ KLÓNOZÁS TELJESEN KÉSZ - Párhuzamos folyamat befejezve'
                    });
                    
                } catch (e) {
                    event.reply('server-clone-res', {
                        success: false,
                        message: `Hiba a jogosultságok beállításakor: ${e.message}`
                    });
                }
            }
        });
    });
}

function applyChannelPermissions(token, channelId, permissionOverwrites, targetGuildId, event) {
    
    const mappedPerms = permissionOverwrites.map(perm => {
        if (perm.type === 0) {
            const targetRoleId = parallelCloneState.roleMap.get(perm.id);
            if (targetRoleId) {
                return {
                    id: targetRoleId,
                    type: perm.type,
                    allow: perm.allow,
                    deny: perm.deny
                };
            }
        }
        return null;
    }).filter(p => p !== null);
    
    if (mappedPerms.length === 0) return;
    
    mappedPerms.forEach((perm, index) => {
        setTimeout(() => {
            const permOptions = {
                hostname: 'discord.com',
                path: `/api/v10/channels/${encodeURIComponent(channelId)}/permissions/${encodeURIComponent(perm.id)}`,
                method: 'PUT',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const permReq = https.request(permOptions, (permRes) => {
                if (permRes.statusCode === 200 || permRes.statusCode === 204) {
                }
            });
            
            permReq.on('error', () => {});
            
            permReq.write(JSON.stringify({
                type: perm.type,
                allow: perm.allow,
                deny: perm.deny
            }));
            
            permReq.end();
        }, index * 300);
    });
}

function updateRolePositions(token, guildId, roleMap, event, callback) {
    const https = require('https');
    
    if (!serverCloningActive) {
        sendParallelLog(event, 'roles', '⛔ Pozíció frissítés leállítva', true);
        if (callback) callback();
        return;
    }
    
    const positions = Array.from(roleMap.values()).sort((a, b) => a.position - b.position);
    
    const options = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${guildId}/roles`,
        method: 'PATCH',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const req = https.request(options, (res) => {
        if (res.statusCode === 200) {
            sendParallelLog(event, 'roles', '✅ Rang pozíciók frissítve');
        } else {
            sendParallelLog(event, 'roles', `⚠️ Pozíció frissítés hiba: ${res.statusCode}`, true);
        }
        if (callback) callback();
    });
    
    req.on('error', (error) => {
        sendParallelLog(event, 'roles', `❌ Pozíció frissítés hiba: ${error.message}`, true);
        if (callback) callback();
    });
    
    req.write(JSON.stringify(positions));
    req.end();
}

function translateCategoryName(categoryName, locale) {
    const translations = {
        'hu-HU': {
        },
        'en-US': {
        }
    };
    
    const translationDict = translations[locale] || translations['en-US'];

    return translationDict[categoryName] || categoryName;
}

function createCategoriesAndChannels(token, sourceGuildId, targetGuildId, event, userLanguage = 'hu') {
    const https = require('https');
    
    const locale = userLanguage === 'hu' ? 'hu-HU' : 'en-US';
    
    event.reply('server-clone-res', { success: true, message: '4. lépés: Kategóriák és csatornák létrehozása...' });

    const sourceOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${sourceGuildId}/channels`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const sourceReq = https.request(sourceOptions, (sourceRes) => {
        let sourceData = '';
        sourceRes.on('data', chunk => sourceData += chunk);
        sourceRes.on('end', () => {
            if (sourceRes.statusCode === 200) {
                try {
                    const channels = JSON.parse(sourceData);
                    const categories = channels.filter(c => c.type === 4);
                    const textChannels = channels.filter(c => c.type === 0);
                    const voiceChannels = channels.filter(c => c.type === 2);
                    
                    event.reply('server-clone-res', { 
                        success: true, 
                        message: `Talált: ${categories.length} kategória, ${textChannels.length} szöveg csatorna, ${voiceChannels.length} hang csatorna` 
                    });
                    

                    let createdCategories = 0;
                    const categoryMap = {};
                    
                    if (categories.length === 0) {
                        event.reply('server-clone-res', { success: true, message: '✓ Nincsenek kategóriák a létrehozáshoz' });
                        createTextAndVoiceChannels(token, textChannels, voiceChannels, {}, targetGuildId, event, [], sourceGuildId);
                        return;
                    }
                    
                    categories.forEach((category, index) => {
                        setTimeout(() => {
                            const createOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${targetGuildId}/channels`,
                                method: 'POST',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const createReq = https.request(createOptions, (createRes) => {
                                let responseData = '';
                                createRes.on('data', chunk => responseData += chunk);
                                createRes.on('end', () => {
                                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                                        const newCategory = JSON.parse(responseData);
                                        categoryMap[category.id] = newCategory.id;
                                        createdCategories++;
                                        
                                        const translatedCategoryName = translateCategoryName(category.name, locale);
                                        
                                        event.reply('server-clone-res', { success: true, message: `✓ Kategória létrehozva: ${translatedCategoryName}` });
                                        
                                        if (createdCategories === categories.length) {
                                            createTextAndVoiceChannels(token, textChannels, voiceChannels, categoryMap, targetGuildId, event, [], sourceGuildId);
                                        }
                                    } else {
                                        event.reply('server-clone-res', { success: false, message: `Failed to create category ${category.name}: ${createRes.statusCode}` });
                                    }
                                });
                            });
                            
                            createReq.on('error', (error) => {
                                event.reply('server-clone-res', { success: false, message: `Error creating category ${category.name}: ${error.message}` });
                            });
                            
                            const translatedCategoryName = translateCategoryName(category.name, locale);
                            
                            const categoryData = {
                                name: translatedCategoryName,
                                type: 4,
                                position: category.position,
                                permission_overwrites: category.permission_overwrites || []
                            };
                            
                            event.reply('server-clone-res', { 
                                success: true, 
                                message: `Debug: Kategória létrehozása: ${translatedCategoryName} (Pozíció: ${category.position})` 
                            });
                            
                            createReq.write(JSON.stringify(categoryData));
                            createReq.end();
                        }, index * 1500);
                    });
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse source channels' });
                    createRoles(token, sourceGuildId, targetGuildId, event, () => {});
                }
            } else {
                event.reply('server-clone-res', { success: false, error: `Failed to get source channels: ${sourceRes.statusCode}` });
                createRoles(token, sourceGuildId, targetGuildId, event, () => {});
            }
        });
    });
    
    sourceReq.end();
}

function createTextAndVoiceChannels(token, textChannels, voiceChannels, categoryMap, targetGuildId, event, targetRoles, sourceGuildId) {
    const https = require('https');
    
    event.reply('server-clone-res', { success: true, message: '5. lépés: Szöveg és hang csatornák létrehozása...' });
    
    const allChannels = [...textChannels, ...voiceChannels];
    
    event.reply('server-clone-res', { 
        success: true, 
        message: `Debug: Összes csatorna: ${allChannels.length} (Szöveg: ${textChannels.length}, Hang: ${voiceChannels.length})` 
    });
    
    if (allChannels.length === 0) {
        event.reply('server-clone-res', { success: true, message: '✓ Nincsenek csatornák a létrehozáshoz' });
        event.reply('server-clone-res', { 
            success: true, 
            message: '=== SZERVER KLÓNOZÁS KÉSZ ===' 
        });
        return;
    }
    
    let createdChannels = 0;
    
    allChannels.forEach((channel, index) => {
        const channelType = channel.type === 2 ? 'Hang' : 'Szöveg';
        
        setTimeout(() => {
            if (!serverCloningActive) {
                event.reply('server-clone-res', { success: false, message: `Csatorna létrehozás leállítva: ${channel.name}` });
                return;
            }
            
            event.reply('server-clone-res', { 
                success: true, 
                message: `Debug: ${channelType} csatorna létrehozása: ${channel.name}` 
            });
        }, index * 1000);
        
        setTimeout(() => {
            if (!serverCloningActive) {
                event.reply('server-clone-res', { success: false, message: `Csatorna létrehozás leállítva: ${channel.name}` });
                return;
            }
            
            const createOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${targetGuildId}/channels`,
                method: 'POST',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const createReq = https.request(createOptions, (createRes) => {
                let responseData = '';
                createRes.on('data', chunk => responseData += chunk);
                createRes.on('end', () => {
                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                        const newChannel = JSON.parse(responseData);
                        createdChannels++;
                        event.reply('server-clone-res', { success: true, message: `✓ Csatorna létrehozva: ${channel.name}` });
                        
                        if (channel.permission_overwrites && channel.permission_overwrites.length > 0) {
                            setTimeout(() => {
                                setupChannelPermissions(token, newChannel.id, channel.permission_overwrites, targetRoles, event, sourceGuildId);
                            }, 2000);
                        }
                        
                        if (createdChannels === allChannels.length) {
                            event.reply('server-clone-res', { 
                                success: true, 
                                message: '=== SZERVER KLÓNOZÁS KÉSZ ===' 
                            });
                            event.reply('server-clone-res', { 
                                success: true, 
                                message: `Összesen: ${allChannels.length} csatorna sikeresen létrehozva` 
                            });
                        }
                    } else {
                        event.reply('server-clone-res', { success: false, message: `Failed to create channel ${channel.name}: ${createRes.statusCode}` });
                    }
                });
            });
            
            createReq.on('error', (error) => {
                event.reply('server-clone-res', { success: false, message: `Error creating channel ${channel.name}: ${error.message}` });
            });
            
            const channelData = {
                name: channel.name,
                type: channel.type,
                topic: channel.topic || '',
                position: channel.position,
                nsfw: channel.nsfw || false,
                rate_limit_per_user: channel.rate_limit_per_user || 0,
                parent_id: channel.parent_id ? categoryMap[channel.parent_id] : null,
                permission_overwrites: channel.permission_overwrites || [],
                bitrate: channel.type === 2 ? (channel.bitrate || 64000) : undefined,
                user_limit: channel.type === 2 ? (channel.user_limit || 0) : undefined
            };
            
            createReq.write(JSON.stringify(channelData));
            createReq.end();
        }, index * 1000);
    });
}


function removeCustomIcons(roleName) {

    return roleName.replace(/<a?:[^>]+:\d+>/g, '').trim();
}

function createRoles(token, sourceGuildId, targetGuildId, event, callback) {
    const https = require('https');
    
    event.reply('server-clone-res', { success: true, message: '6. lépés: Rangok létrehozása...' });
    
    const roleOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${sourceGuildId}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const roleReq = https.request(roleOptions, (roleRes) => {
        let roleData = '';
        roleRes.on('data', chunk => roleData += chunk);
        roleRes.on('end', () => {
            if (roleRes.statusCode === 200) {
                try {
                    const roles = JSON.parse(roleData);
                    const cloneableRoles = roles.filter(r => r.name !== '@everyone');
                    
                    cloneableRoles.sort((a, b) => b.position - a.position);
                    
                    event.reply('server-clone-res', { 
                        success: true, 
                        message: `Debug: Rangok sorrendje (magasabb előre): ${cloneableRoles.map(r => `${r.name}(${r.position})`).join(', ')}` 
                    });
                    
                    event.reply('server-clone-res', { 
                        success: true, 
                        message: `Debug: Összes rang: ${roles.length}, Klónozható: ${cloneableRoles.length}` 
                    });
                    
                    if (cloneableRoles.length === 0) {
                        event.reply('server-clone-res', { success: true, message: '✓ Nincsenek rangok a létrehozáshoz' });
                        if (callback) callback();
                        return;
                    }
                    
                    event.reply('server-clone-res', { 
                        success: true, 
                        message: `${cloneableRoles.length} rang klónozása...` 
                    });
                    
                    let createdRoles = 0;
                    let failedRoles = 0;
                    const createdRoleMap = new Map();
                    
                    cloneableRoles.forEach((role, index) => {
                        event.reply('server-clone-res', { 
                            success: true, 
                            message: `Debug: Rang létrehozása: ${role.name} (Szín: ${role.color}, Jogosultság: ${role.permissions}, Pozíció: ${role.position})` 
                        });
                        
                        setTimeout(() => {
                            if (!serverCloningActive) {
                                return;
                            }
                            
                            const createOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${targetGuildId}/roles`,
                                method: 'POST',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const createReq = https.request(createOptions, (createRes) => {
                                let responseData = '';
                                createRes.on('data', chunk => responseData += chunk);
                                createRes.on('end', () => {
                                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                                        createdRoles++;
                                        const createdRole = JSON.parse(responseData);
                                        createdRoleMap.set(role.name, {
                                            id: createdRole.id,
                                            originalPosition: role.position,
                                            targetPosition: Math.max(1, role.position - 10)
                                        });
                                        
                                        event.reply('server-clone-res', { 
                                            success: true, 
                                            message: `✓ Rang létrehozva: ${role.name} (ID: ${createdRole.id})` 
                                        });

                                        if (createdRoles + failedRoles === cloneableRoles.length) {
                                            event.reply('server-clone-res', { 
                                                success: true, 
                                                message: `✓ ${createdRoles} rang létrehozva. Pozíciók beállítása...` 
                                            });

                                            updateRolePositions(token, targetGuildId, createdRoleMap, event, callback);
                                        }
                                    } else if (createRes.statusCode === 429) {
                                        event.reply('server-clone-res', { 
                                            success: false, 
                                            message: `Rate limit elérve a(z) ${role.name} rangnál, újrapróbálkozás 5 másodperc múlva...` 
                                        });
                                        
                                        setTimeout(() => {
                                            setTimeout(() => {
                                                const retryReq = https.request(createOptions, (retryRes) => {
                                                    let retryData = '';
                                                    retryRes.on('data', chunk => retryData += chunk);
                                                    retryRes.on('end', () => {
                                                        if (retryRes.statusCode === 200 || retryRes.statusCode === 201) {
                                                            createdRoles++;
                                                            event.reply('server-clone-res', { 
                                                                success: true, 
                                                                message: `✓ Rang létrehozva (újrapróbálkozás után): ${role.name}` 
                                                            });
                                                        } else {
                                                            failedRoles++;
                                                            event.reply('server-clone-res', { 
                                                                success: false, 
                                                                message: `Failed to create role ${role.name} after retry: ${retryRes.statusCode}` 
                                                            });
                                                        }
                                                        
                                                        if (createdRoles + failedRoles === cloneableRoles.length) {
                                                            event.reply('server-clone-res', { 
                                                                success: true, 
                                                                message: `✓ Rangok létrehozása kész: ${createdRoles} sikeres, ${failedRoles} sikertelen` 
                                                            });
                                                            
                                                            if (callback) callback();
                                                        }
                                                    });
                                                });
                                                
                                                retryReq.on('error', (error) => {
                                                    failedRoles++;
                                                    event.reply('server-clone-res', { 
                                                        success: false, 
                                                        message: `Error creating role ${role.name} after retry: ${error.message}` 
                                                    });
                                                    
                                                    if (createdRoles + failedRoles === cloneableRoles.length) {
                                                        event.reply('server-clone-res', { 
                                                            success: true, 
                                                            message: `✓ Rangok létrehozása kész: ${createdRoles} sikeres, ${failedRoles} sikertelen` 
                                                        });
                                                        
                                                        if (callback) callback();
                                                    }
                                                });
                                                
                                                retryReq.write(JSON.stringify(roleData));
                                                retryReq.end();
                                            }, 1000);
                                        }, 5000);
                                    } else {
                                        failedRoles++;
                                        if (createRes.statusCode === 403) {
                                            event.reply('server-clone-res', { 
                                                success: false, 
                                                message: `403 - Nincs jogosultság a(z) ${role.name} rang létrehozásához (valószínűleg magasabb pozíciójú)` 
                                            });
                                        } else {
                                            event.reply('server-clone-res', { success: false, message: `Failed to create role ${role.name}: ${createRes.statusCode}` });
                                        }
                                        
                                        if (createdRoles + failedRoles === cloneableRoles.length) {
                                            event.reply('server-clone-res', { 
                                                success: true, 
                                                message: `✓ Rangok létrehozása kész: ${createdRoles} sikeres, ${failedRoles} sikertelen` 
                                            });
                                            
                                            if (callback) callback();
                                        }
                                    }
                                });
                            });
                            
                            createReq.on('error', (error) => {
                                failedRoles++;
                                event.reply('server-clone-res', { success: false, message: `Error creating role ${role.name}: ${error.message}` });
                                
                                if (createdRoles + failedRoles === cloneableRoles.length) {
                                    event.reply('server-clone-res', { 
                                        success: true, 
                                        message: `✓ Rangok létrehozása kész: ${createdRoles} sikeres, ${failedRoles} sikertelen` 
                                    });
                                    
                                    if (callback) callback();
                                }
                            });
                            
                            const roleData = {
                                name: role.name,
                                color: role.color,
                                hoist: role.hoist,
                                permissions: role.permissions.toString(),
                                mentionable: role.mentionable,
                                icon: null,
                                unicode_emoji: role.unicode_emoji || null
                            };
                            
                            event.reply('server-clone-res', { 
                                success: true, 
                                message: `Debug: Rang adatok küldése: ${JSON.stringify(roleData)}` 
                            });
                            
                            createReq.write(JSON.stringify(roleData));
                            createReq.end();
                        }, index * 3000);
                    });
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse roles data' });
                    if (callback) callback();
                }
            } else {
                event.reply('server-clone-res', { success: false, error: `Failed to get roles: ${roleRes.statusCode}` });
                if (callback) callback();
            }
        });
    });
    
    roleReq.end();
}

function updateRolePositions(token, guildId, roleMap, event, callback) {
    const https = require('https');
    
    if (!serverCloningActive) {
        event.reply('server-clone-res', { success: false, message: 'Pozíció frissítés kihagyva - klónozás leállítva' });
        if (callback) callback();
        return;
    }
    
    event.reply('server-clone-res', { 
        success: true, 
        message: `${roleMap.size} rang pozíciójának beállítása...` 
    });
    
    let updatedPositions = 0;
    let failedUpdates = 0;
    
    const rolesToUpdate = Array.from(roleMap.entries())
        .map(([name, data]) => ({ name, ...data }))
        .sort((a, b) => b.originalPosition - a.originalPosition);
    
    rolesToUpdate.forEach((role, index) => {
        setTimeout(() => {

            if (!serverCloningActive) {
                return;
            }
            
            const updateOptions = {
                hostname: 'discord.com',
                path: `/api/v10/guilds/${guildId}/roles/${role.id}`,
                method: 'PATCH',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const updateReq = https.request(updateOptions, (updateRes) => {
                let responseData = '';
                updateRes.on('data', chunk => responseData += chunk);
                updateRes.on('end', () => {
                    if (updateRes.statusCode === 200) {
                        updatedPositions++;
                        event.reply('server-clone-res', { 
                            success: true, 
                            message: `✓ Pozíció beállítva: ${role.name} -> ${role.targetPosition}` 
                        });
                    } else if (updateRes.statusCode === 429) {
                        const retryAfter = updateRes.headers['retry-after'] || 5;
                        event.reply('server-clone-res', { 
                            success: false, 
                            message: `Rate limit a(z) ${role.name} pozíciónál, retry ${retryAfter}s...` 
                        });
                        setTimeout(() => {
                            const retryReq = https.request(updateOptions, (retryRes) => {
                                if (retryRes.statusCode === 200) {
                                    updatedPositions++;
                                    event.reply('server-clone-res', { success: true, message: `✓ Pozíció beállítva (retry): ${role.name}` });
                                } else {
                                    failedUpdates++;
                                    event.reply('server-clone-res', { success: false, message: `Failed position update (retry): ${role.name}: ${retryRes.statusCode}` });
                                }
                                checkComplete();
                            });
                            retryReq.end();
                        }, retryAfter * 1000);
                        return;
                    } else {
                        failedUpdates++;
                        event.reply('server-clone-res', { 
                            success: false, 
                            message: `Failed to update position for ${role.name}: ${updateRes.statusCode}` 
                        });
                    }
                    checkComplete();
                });
            });
            
            updateReq.on('error', (error) => {
                failedUpdates++;
                event.reply('server-clone-res', { 
                    success: false, 
                    message: `Error updating position for ${role.name}: ${error.message}` 
                });
                checkComplete();
            });
            
            const updateData = { position: role.targetPosition };
            updateReq.write(JSON.stringify(updateData));
            updateReq.end();
            
        }, index * 2000);
    });
    
    function checkComplete() {
        if (updatedPositions + failedUpdates === rolesToUpdate.length) {
            event.reply('server-clone-res', { 
                success: true, 
                message: `✓ Rangok létrehozása kész: ${updatedPositions} pozíció beállítva, ${failedUpdates} sikertelen` 
            });
            if (callback) callback();
        }
    }
}

function setupCategoryPermissions(token, categoryId, permissionOverwrites, targetRoles, event) {
    const https = require('https');
    
    if (!permissionOverwrites || permissionOverwrites.length === 0) {
        event.reply('server-clone-res', { success: true, message: `✓ Nincsenek jogosultságok a kategóriához: ${categoryId}` });
        return;
    }
    
    event.reply('server-clone-res', { 
        success: true, 
        message: `Jogosultságok beállítása kategóriához: ${permissionOverwrites.length} jogosultság` 
    });
    
    let updatedPermissions = 0;
    
    permissionOverwrites.forEach((overwrite, index) => {
        setTimeout(() => {
            if (!serverCloningActive) {
                event.reply('server-clone-res', { success: false, message: 'Kategória jogosultság beállítás leállítva!' });
                return;
            }
            const targetRole = targetRoles.find(r => r.name === (overwrite.id ? targetRoles.find(tr => tr.id === overwrite.id)?.name : null));
            
            if (!targetRole) {
                event.reply('server-clone-res', { success: false, message: `Nem található a rang a jogosultsághoz: ${overwrite.id}` });
                return;
            }
            
            const permissionData = {
                allow: overwrite.allow,
                deny: overwrite.deny,
                type: overwrite.type
            };
            
            const options = {
                hostname: 'discord.com',
                path: `/api/v10/channels/${categoryId}/permissions/${targetRole.id}`,
                method: 'PUT',
                headers: {
                    'Authorization': token,
                    'Content-Type': 'application/json'
                }
            };
            
            const req = https.request(options, (res) => {
                if (res.statusCode === 200 || res.statusCode === 204) {
                    updatedPermissions++;
                    event.reply('server-clone-res', { 
                        success: true, 
                        message: `✓ Jogosultság beállítva: ${targetRole.name} -> ${categoryId}` 
                    });
                } else if (res.statusCode === 429) {
                    const retryAfter = res.headers['retry-after'] || 5;
                    event.reply('server-clone-res', { 
                        success: false, 
                        message: `Rate limit a(z) ${targetRole.name} jogosultságnál, újrapróbálkozás ${retryAfter}s múlva...` 
                    });
                    setTimeout(() => {
                        if (!serverCloningActive) return;
                        const retryReq = https.request(options, (retryRes) => {
                            if (retryRes.statusCode === 200 || retryRes.statusCode === 204) {
                                updatedPermissions++;
                                event.reply('server-clone-res', { 
                                    success: true, 
                                    message: `✓ Jogosultság beállítva (retry): ${targetRole.name}` 
                                });
                            } else {
                                event.reply('server-clone-res', { 
                                    success: false, 
                                    message: `Failed to set permission for ${targetRole.name} (retry): ${retryRes.statusCode}` 
                                });
                            }
                        });
                        retryReq.on('error', (error) => {
                            event.reply('server-clone-res', { 
                                success: false, 
                                message: `Error setting permission (retry): ${error.message}` 
                            });
                        });
                        retryReq.write(JSON.stringify(permissionData));
                        retryReq.end();
                    }, retryAfter * 1000);
                } else {
                    event.reply('server-clone-res', { 
                        success: false, 
                        message: `Failed to set permission for ${targetRole.name}: ${res.statusCode}` 
                    });
                }
            });
            
            req.on('error', (error) => {
                event.reply('server-clone-res', { 
                    success: false, 
                    message: `Error setting permission: ${error.message}` 
                });
            });
            
            req.write(JSON.stringify(permissionData));
            req.end();
        }, index * 2000);
    });
}

function setupChannelPermissions(token, channelId, permissionOverwrites, targetRoles, event, sourceGuildId) {
    const https = require('https');
    
    if (!permissionOverwrites || permissionOverwrites.length === 0) {
        event.reply('server-clone-res', { success: true, message: `✓ Nincsenek jogosultságok a csatornához: ${channelId}` });
        return;
    }
    
    event.reply('server-clone-res', { 
        success: true, 
        message: `Jogosultságok beállítása csatornához: ${permissionOverwrites.length} jogosultság` 
    });
    
    const channelOptions = {
        hostname: 'discord.com',
        path: `/api/v10/channels/${channelId}`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const channelReq = https.request(channelOptions, (channelRes) => {
        let channelData = '';
        channelRes.on('data', chunk => channelData += chunk);
        channelRes.on('end', () => {
            if (channelRes.statusCode === 200) {
                try {
                    const channelInfo = JSON.parse(channelData);
                    const targetGuildId = channelInfo.guild_id;
                    
                    const roleOptions = {
                        hostname: 'discord.com',
                        path: `/api/v10/guilds/${targetGuildId}/roles`,
                        method: 'GET',
                        headers: {
                            'Authorization': token,
                            'Content-Type': 'application/json'
                        }
                    };
                    
                    const roleReq = https.request(roleOptions, (roleRes) => {
                        let roleData = '';
                        roleRes.on('data', chunk => roleData += chunk);
                        roleRes.on('end', () => {
                            if (roleRes.statusCode === 200) {
                                try {
                                    const actualRoles = JSON.parse(roleData);
                                    
                                    event.reply('server-clone-res', { 
                                        success: true, 
                                        message: `Debug: Elérhető rangok: ${actualRoles.map(r => r.name).join(', ')}` 
                                    });
                                    
                                    let updatedPermissions = 0;
                                    let failedPermissions = 0;
                                    
                                    permissionOverwrites.forEach((overwrite, index) => {
                                        setTimeout(() => {
                                            if (!serverCloningActive) {
                                                event.reply('server-clone-res', { success: false, message: 'Jogosultság beállítás leállítva!' });
                                                return;
                                            }
                                            event.reply('server-clone-res', { 
                                                success: true, 
                                                message: `Debug: Jogosultság ${index}: ID=${overwrite.id}, Type=${overwrite.type}, Allow=${overwrite.allow}, Deny=${overwrite.deny}` 
                                            });
                                            
                                            let targetRole = null;
                                            if (overwrite.type === 0) {
                                                if (overwrite.id === sourceGuildId) {
                                                    targetRole = actualRoles.find(r => r.name === '@everyone');
                                                    event.reply('server-clone-res', { 
                                                        success: true, 
                                                        message: `Debug: @everyone rang megtalálva` 
                                                    });
                                                    
                                                    if (targetRole) {
                                                        applyPermissionOverwrite(token, channelId, targetRole.id, overwrite, event, () => {
                                                            updatedPermissions++;
                                                            event.reply('server-clone-res', { 
                                                                success: true, 
                                                                message: `✓ Jogosultság beállítva: @everyone -> Allow: ${overwrite.allow}, Deny: ${overwrite.deny}` 
                                                            });
                                                            checkIfComplete();
                                                        });
                                                    } else {
                                                        failedPermissions++;
                                                        checkIfComplete();
                                                    }
                                                } else {
                                                    const sourceRoleOptions = {
                                                        hostname: 'discord.com',
                                                        path: `/api/v10/guilds/${sourceGuildId}/roles/${overwrite.id}`,
                                                        method: 'GET',
                                                        headers: {
                                                            'Authorization': token,
                                                            'Content-Type': 'application/json'
                                                        }
                                                    };
                                                    
                                                    const sourceRoleReq = https.request(sourceRoleOptions, (sourceRoleRes) => {
                                                        let sourceRoleData = '';
                                                        sourceRoleRes.on('data', chunk => sourceRoleData += chunk);
                                                        sourceRoleRes.on('end', () => {
                                                            if (sourceRoleRes.statusCode === 200) {
                                                                try {
                                                                    const sourceRole = JSON.parse(sourceRoleData);
                                                                    
                                                                    event.reply('server-clone-res', { 
                                                                        success: true, 
                                                                        message: `Debug: Forrás rang: ${sourceRole.name} (ID: ${sourceRole.id})` 
                                                                    });
                                                                    
                                                                    targetRole = actualRoles.find(r => r.name === sourceRole.name);
                                                                    
                                                                    if (!targetRole) {
                                                                        event.reply('server-clone-res', { 
                                                                            success: false, 
                                                                            message: `Nem található a rang: ${sourceRole.name}` 
                                                                        });
                                                                        failedPermissions++;
                                                                        checkIfComplete();
                                                                        return;
                                                                    }
                                                                    
                                                                    event.reply('server-clone-res', { 
                                                                        success: true, 
                                                                        message: `Debug: Cél rang megtalálva: ${targetRole.name} (ID: ${targetRole.id})` 
                                                                    });
                                                                    
                                                                    applyPermissionOverwrite(token, channelId, targetRole.id, overwrite, event, () => {
                                                                        updatedPermissions++;
                                                                        event.reply('server-clone-res', { 
                                                                            success: true, 
                                                                            message: `✓ Jogosultság beállítva: ${targetRole.name} -> Allow: ${overwrite.allow}, Deny: ${overwrite.deny}` 
                                                                        });
                                                                        checkIfComplete();
                                                                    });
                                                                    
                                                                } catch (e) {
                                                                    event.reply('server-clone-res', { success: false, error: 'Failed to parse source role data' });
                                                                    failedPermissions++;
                                                                    checkIfComplete();
                                                                }
                                                            } else {
                                                                event.reply('server-clone-res', { 
                                                                    success: false, 
                                                                    message: `Failed to get source role ${overwrite.id}: ${sourceRoleRes.statusCode}` 
                                                                });
                                                                failedPermissions++;
                                                                checkIfComplete();
                                                            }
                                                        });
                                                    });
                                                    
                                                    sourceRoleReq.on('error', (error) => {
                                                        event.reply('server-clone-res', { 
                                                            success: false, 
                                                            message: `Error getting source role: ${error.message}` 
                                                        });
                                                        failedPermissions++;
                                                        checkIfComplete();
                                                    });
                                                    
                                                    sourceRoleReq.end();
                                                }
                                            } else if (overwrite.type === 1) {
                                                const permissionData = {
                                                    allow: overwrite.allow,
                                                    deny: overwrite.deny
                                                };
                                                
                                                const memberPermReq = https.request({
                                                    hostname: 'discord.com',
                                                    path: `/api/v10/channels/${channel.id}/permissions/${overwrite.id}`,
                                                    method: 'PUT',
                                                    headers: {
                                                        'Authorization': token,
                                                        'Content-Type': 'application/json'
                                                    }
                                                }, (memberPermRes) => {
                                                    if (memberPermRes.statusCode === 204) {
                                                        event.reply('server-clone-res', { 
                                                            success: true, 
                                                            message: `✓ Tag jogosultság beállítva: ${sourceRole.name} -> Member ${overwrite.id}` 
                                                        });
                                                        successfulPermissions++;
                                                    } else {
                                                        event.reply('server-clone-res', { 
                                                            success: false, 
                                                            message: `Failed to set member permission: ${memberPermRes.statusCode}` 
                                                        });
                                                        failedPermissions++;
                                                    }
                                                    checkIfComplete();
                                                });
                                                
                                                memberPermReq.on('error', (error) => {
                                                    event.reply('server-clone-res', { 
                                                        success: false, 
                                                        message: `Error setting member permission: ${error.message}` 
                                                    });
                                                    failedPermissions++;
                                                    checkIfComplete();
                                                });
                                                
                                                memberPermReq.write(JSON.stringify(permissionData));
                                                memberPermReq.end();
                                            }
                                            
                                            function checkIfComplete() {
                                                if (updatedPermissions + failedPermissions === permissionOverwrites.length) {
                                                    event.reply('server-clone-res', { 
                                                        success: true, 
                                                        message: `✓ Összes jogosultság beállítva: ${updatedPermissions}/${permissionOverwrites.length} sikeres, ${failedPermissions} sikertelen` 
                                                    });
                                                }
                                            }
                                            
                                        }, index * 2500);
                                    });
                                } catch (e) {
                                    event.reply('server-clone-res', { success: false, error: 'Failed to parse roles data' });
                                }
                            } else {
                                event.reply('server-clone-res', { success: false, error: `Failed to get roles: ${roleRes.statusCode}` });
                            }
                        });
                    });
                    
                    roleReq.end();
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse channel data' });
                }
            } else {
                event.reply('server-clone-res', { success: false, error: `Failed to get channel info: ${channelRes.statusCode}` });
            }
        });
    });
    
    channelReq.end();
}

function applyPermissionOverwrite(token, channelId, targetId, overwrite, event, callback) {
    const https = require('https');
    
    const permissionData = {
        allow: overwrite.allow,
        deny: overwrite.deny,
        type: overwrite.type
    };
    
    const options = {
        hostname: 'discord.com',
        path: `/api/v10/channels/${channelId}/permissions/${targetId}`,
        method: 'PUT',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const req = https.request(options, (res) => {
        if (res.statusCode === 200 || res.statusCode === 204) {
            if (callback) callback();
        } else if (res.statusCode === 429) {
            const retryAfter = res.headers['retry-after'] || 5;
            event.reply('server-clone-res', { 
                success: false, 
                message: `Rate limit a jogosultságnál, újrapróbálkozás ${retryAfter}s múlva...` 
            });
            setTimeout(() => {
                if (!serverCloningActive) return;
                const retryReq = https.request(options, (retryRes) => {
                    if (retryRes.statusCode === 200 || retryRes.statusCode === 204) {
                        if (callback) callback();
                    } else {
                        event.reply('server-clone-res', { 
                            success: false, 
                            message: `Failed to set permission (retry): ${retryRes.statusCode}` 
                        });
                    }
                });
                retryReq.on('error', (error) => {
                    event.reply('server-clone-res', { 
                        success: false, 
                        message: `Error setting permission (retry): ${error.message}` 
                    });
                });
                retryReq.write(JSON.stringify(permissionData));
                retryReq.end();
            }, retryAfter * 1000);
        } else {
            event.reply('server-clone-res', { 
                success: false, 
                message: `Failed to set permission for ${targetId}: ${res.statusCode}` 
            });
        }
    });
    
    req.on('error', (error) => {
        event.reply('server-clone-res', { 
            success: false, 
            message: `Error setting permission: ${error.message}` 
        });
    });
    
    req.write(JSON.stringify(permissionData));
    req.end();
}

function wipeServer(token, guildId, event, callback) {
    const https = require('https');
    
    event.reply('server-clone-res', { success: true, message: 'Deleting all channels and roles...' });

    const channelOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${guildId}/channels`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const channelReq = https.request(channelOptions, (channelRes) => {
        let channelData = '';
        channelRes.on('data', chunk => channelData += chunk);
        channelRes.on('end', () => {
            if (channelRes.statusCode === 200) {
                try {
                    const channels = JSON.parse(channelData);
                    let deletedChannels = 0;
                    
                    channels.forEach((channel, index) => {
                        setTimeout(() => {
                            const deleteOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/channels/${channel.id}`,
                                method: 'DELETE',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                    deletedChannels++;
                                    if (deletedChannels === channels.length) {
                                        event.reply('server-clone-res', { success: true, message: `Deleted ${deletedChannels} channels` });
                                        deleteAllRoles(token, guildId, event, callback);
                                    }
                                }
                            });
                            
                            deleteReq.end();
                        }, index * 100);
                    });
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse channels for deletion' });
                    callback();
                }
            }
        });
    });
    
    channelReq.end();
}

function deleteAllRoles(token, guildId, event, callback) {
    const https = require('https');
    
    const roleOptions = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${guildId}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const roleReq = https.request(roleOptions, (roleRes) => {
        let roleData = '';
        roleRes.on('data', chunk => roleData += chunk);
        roleRes.on('end', () => {
            if (roleRes.statusCode === 200) {
                try {
                    const roles = JSON.parse(roleData);
                    const deletableRoles = roles.filter(r => r.name !== '@everyone');
                    let deletedRoles = 0;
                    
                    event.reply('server-clone-res', { success: true, message: `Deleting ${deletableRoles.length} roles...` });
                    
                    deletableRoles.forEach((role, index) => {
                        setTimeout(() => {
                            const deleteOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${guildId}/roles/${role.id}`,
                                method: 'DELETE',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const deleteReq = https.request(deleteOptions, (deleteRes) => {
                                if (deleteRes.statusCode === 200 || deleteRes.statusCode === 204) {
                                    deletedRoles++;
                                    if (deletedRoles === deletableRoles.length) {
                                        event.reply('server-clone-res', { success: true, message: `Deleted ${deletedRoles} roles. Server wiped successfully!` });
                                        callback();
                                    }
                                }
                            });
                            
                            deleteReq.end();
                        }, index * 100);
                    });
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse roles for deletion' });
                    callback();
                }
            }
        });
    });
    
    roleReq.end();
}

function cloneChannels(token, sourceGuildId, targetGuildId, event) {
    const https = require('https');
    
    const options = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${sourceGuildId}/channels`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const req = https.request(options, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
            if (res.statusCode === 200) {
                try {
                    const channels = JSON.parse(data);
                    const categories = channels.filter(c => c.type === 4);
                    const textChannels = channels.filter(c => c.type === 0);
                    const voiceChannels = channels.filter(c => c.type === 2);
                    
                    event.reply('server-clone-res', { success: true, message: `Cloning ${categories.length} categories, ${textChannels.length} text channels, ${voiceChannels.length} voice channels...` });
                    
                    categories.forEach((category, index) => {
                        setTimeout(() => {
                            const createOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${targetGuildId}/channels`,
                                method: 'POST',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const createReq = https.request(createOptions, (createRes) => {
                                if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                                    event.reply('server-clone-res', { success: true, message: `Created category: ${category.name}` });
                                    category.newId = JSON.parse(createRes.response || '{}').id;
                                } else {
                                    event.reply('server-clone-res', { success: false, message: `Failed to create category ${category.name}: ${createRes.statusCode}` });
                                }
                            });
                            
                            const categoryData = {
                                name: category.name,
                                type: 4,
                                position: category.position,
                                permission_overwrites: category.permission_overwrites || []
                            };
                            
                            createReq.write(JSON.stringify(categoryData));
                            createReq.end();
                        }, index * 200);
                    });

                    setTimeout(() => {
                        const allChannels = [...textChannels, ...voiceChannels];
                        allChannels.forEach((channel, index) => {
                            setTimeout(() => {
                                const createOptions = {
                                    hostname: 'discord.com',
                                    path: `/api/v10/guilds/${targetGuildId}/channels`,
                                    method: 'POST',
                                    headers: {
                                        'Authorization': token,
                                        'Content-Type': 'application/json'
                                    }
                                };
                                
                                const createReq = https.request(createOptions, (createRes) => {
                                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                                        event.reply('server-clone-res', { success: true, message: `Created channel: ${channel.name}` });
                                    } else {
                                        event.reply('server-clone-res', { success: false, message: `Failed to create channel ${channel.name}: ${createRes.statusCode}` });
                                    }
                                });
                                
                                const newParentId = channel.parent_id ? 
                                    categories.find(c => c.id === channel.parent_id)?.newId : null;
                                
                                const channelData = {
                                    name: channel.name,
                                    type: channel.type,
                                    topic: channel.topic || '',
                                    position: channel.position,
                                    nsfw: channel.nsfw || false,
                                    rate_limit_per_user: channel.rate_limit_per_user || 0,
                                    parent_id: newParentId,
                                    permission_overwrites: channel.permission_overwrites || [],
                                    bitrate: channel.type === 2 ? (channel.bitrate || 64000) : undefined,
                                    user_limit: channel.type === 2 ? (channel.user_limit || 0) : undefined,
                                    default_auto_archive_duration: channel.type === 0 ? channel.default_auto_archive_duration : undefined,
                                    default_thread_rate_limit_per_user: channel.type === 0 ? channel.default_thread_rate_limit_per_user : undefined
                                };
                                
                                createReq.write(JSON.stringify(channelData));
                                createReq.end();
                            }, index * 300);
                        });
                    }, categories.length * 200 + 1000);
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse channels data' });
                }
            }
        });
    });
    
    req.end();
}

function cloneRoles(token, sourceGuildId, targetGuildId, event) {
    const https = require('https');
    
    const options = {
        hostname: 'discord.com',
        path: `/api/v10/guilds/${sourceGuildId}/roles`,
        method: 'GET',
        headers: {
            'Authorization': token,
            'Content-Type': 'application/json'
        }
    };
    
    const req = https.request(options, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
            if (res.statusCode === 200) {
                try {
                    const roles = JSON.parse(data);
                    const cloneableRoles = roles.filter(r => r.name !== '@everyone');
                    
                    const everyoneRole = roles.find(r => r.name === '@everyone');
                    if (everyoneRole) {
                        const getTargetRolesOptions = {
                            hostname: 'discord.com',
                            path: `/api/v10/guilds/${targetGuildId}/roles`,
                            method: 'GET',
                            headers: {
                                'Authorization': token,
                                'Content-Type': 'application/json'
                            }
                        };
                        
                        const getTargetRolesReq = https.request(getTargetRolesOptions, (getTargetRes) => {
                            let targetData = '';
                            getTargetRes.on('data', chunk => targetData += chunk);
                            getTargetRes.on('end', () => {
                                if (getTargetRes.statusCode === 200) {
                                    try {
                                        const targetRoles = JSON.parse(targetData);
                                        const targetEveryoneRole = targetRoles.find(r => r.name === '@everyone');
                                        
                                        if (targetEveryoneRole) {
                                            const updateOptions = {
                                                hostname: 'discord.com',
                                                path: `/api/v10/guilds/${targetGuildId}/roles/${targetEveryoneRole.id}`,
                                                method: 'PATCH',
                                                headers: {
                                                    'Authorization': token,
                                                    'Content-Type': 'application/json'
                                                }
                                            };
                                            
                                            const updateReq = https.request(updateOptions, (updateRes) => {
                                                let updateData = '';
                                                updateRes.on('data', chunk => updateData += chunk);
                                                updateRes.on('end', () => {
                                                    if (updateRes.statusCode === 200) {
                                                        event.reply('server-clone-res', { success: true, message: `Updated @everyone role permissions` });
                                                    } else {
                                                        event.reply('server-clone-res', { success: false, message: `Failed to update @everyone permissions: ${updateRes.statusCode}` });
                                                        if (updateData) {
                                                            event.reply('server-clone-res', { success: false, message: `Error details: ${updateData}` });
                                                        }
                                                    }
                                                });
                                            });
                                            
                                            updateReq.on('error', (error) => {
                                                event.reply('server-clone-res', { success: false, message: `Error updating @everyone permissions: ${error.message}` });
                                            });
                                            
                                            const everyoneData = {
                                                permissions: everyoneRole.permissions
                                            };
                                            
                                            updateReq.write(JSON.stringify(everyoneData));
                                            updateReq.end();
                                        } else {
                                            event.reply('server-clone-res', { success: false, message: `@everyone role not found in target server` });
                                        }
                                    } catch (e) {
                                        event.reply('server-clone-res', { success: false, message: `Error parsing target roles: ${e.message}` });
                                    }
                                } else {
                                    event.reply('server-clone-res', { success: false, message: `Failed to get target roles: ${getTargetRes.statusCode}` });
                                }
                            });
                        });
                        
                        getTargetRolesReq.on('error', (error) => {
                            event.reply('server-clone-res', { success: false, message: `Error getting target roles: ${error.message}` });
                        });
                        
                        getTargetRolesReq.end();
                    }
                    
                    event.reply('server-clone-res', { success: true, message: `Cloning ${cloneableRoles.length} roles...` });
                    
                    cloneableRoles.forEach((role, index) => {
                        setTimeout(() => {
                            const createOptions = {
                                hostname: 'discord.com',
                                path: `/api/v10/guilds/${targetGuildId}/roles`,
                                method: 'POST',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const createReq = https.request(createOptions, (createRes) => {
                                let responseData = '';
                                createRes.on('data', chunk => responseData += chunk);
                                createRes.on('end', () => {
                                    if (createRes.statusCode === 200 || createRes.statusCode === 201) {
                                        event.reply('server-clone-res', { success: true, message: `Created role: ${role.name}` });
                                    } else {
                                        event.reply('server-clone-res', { success: false, message: `Failed to create role ${role.name}: ${createRes.statusCode}` });
                                    }
                                });
                            });
                            
                            createReq.on('error', (error) => {
                                event.reply('server-clone-res', { success: false, message: `Error creating role ${role.name}: ${error.message}` });
                            });
                            
                            const roleData = {
                                name: role.name,
                                color: role.color,
                                hoist: role.hoist,
                                position: role.position,
                                permissions: role.permissions,
                                mentionable: role.mentionable,
                                icon: role.icon || null,
                                unicode_emoji: role.unicode_emoji || null
                            };
                            
                            createReq.write(JSON.stringify(roleData));
                            createReq.end();
                        }, index * 300);
                    });
                } catch (e) {
                    event.reply('server-clone-res', { success: false, error: 'Failed to parse roles data' });
                }
            }
        });
    });
    
    req.end();
}

function clonePermissions(token, sourceGuildId, targetGuildId, event) {
    event.reply('server-clone-res', { success: true, message: 'Cloning additional server settings...' });
}

let nukerRunning = false;
ipcMain.on('start-full-nuke', async (event, token, guildId) => {
    nukerRunning = true;
    event.reply('nuker-response', { success: true, message: '=== FULL NUKE STARTED ===' });

    ipcMain.emit('delete-all-channels', event, token, guildId);
    
    setTimeout(() => {
        if (nukerRunning) {
            ipcMain.emit('delete-all-roles', event, token, guildId);
        }
    }, 2000);
    
    setTimeout(() => {
        if (nukerRunning) {
            ipcMain.emit('start-mass-ban', event, token, guildId);
        }
    }, 4000);
    
    setTimeout(() => {
        if (nukerRunning) {
            nukerRunning = false;
            event.reply('nuker-response', { success: true, message: '=== FULL NUKE COMPLETED ===' });
        }
    }, 10000);
});
ipcMain.on('stop-full-nuke', () => {
    nukerRunning = false;
});

