function loadConfig() {
    try {
        if (fs.existsSync(CONFIG_PATH)) {
            const data = fs.readFileSync(CONFIG_PATH, 'utf8');
            return JSON.parse(data);
        }
    } catch (e) {
    }
    return { users: {} };
}

function saveConfig(config) {
    try {
        if (!fs.existsSync(CONFIG_DIR)) {
            fs.mkdirSync(CONFIG_DIR, { recursive: true });
        }
        fs.writeFileSync(CONFIG_PATH, JSON.stringify(config, null, 2), 'utf8');
    } catch (e) {
    }
}

function getThemeForHWID(hwid) {
    const config = loadConfig();
    return config.users[hwid]?.theme || null;
}

function getCustomColorsForHWID(hwid) {
    const config = loadConfig();
    return config.users[hwid]?.customColors || null;
}

function saveThemeForHWID(hwid, theme, customColors) {
    const config = loadConfig();
    if (!config.users[hwid]) {
        config.users[hwid] = {};
    }
    config.users[hwid].theme = theme;
    if (customColors) config.users[hwid].customColors = customColors;
    saveConfig(config);
}
function getLanguageForHWID(hwid) {
    const config = loadConfig();
    return config.users[hwid]?.language || null;
}

function saveLanguageForHWID(hwid, language) {
    const config = loadConfig();
    if (!config.users[hwid]) {
        config.users[hwid] = {};
    }
    config.users[hwid].language = language;
    saveConfig(config);
}

function getAnimationForHWID(hwid) {
    const config = loadConfig();
    return config.users[hwid]?.animation || null;
}

function saveAnimationForHWID(hwid, animation) {
    const config = loadConfig();
    if (!config.users[hwid]) {
        config.users[hwid] = {};
    }
    config.users[hwid].animation = animation;
    saveConfig(config);
}

function getIconForHWID(hwid) {
    const config = loadConfig();
    return config.users[hwid]?.icon || 'icon.ico';
}

function saveIconForHWID(hwid, icon) {
    const config = loadConfig();
    if (!config.users[hwid]) {
        config.users[hwid] = {};
    }
    config.users[hwid].icon = icon;
    saveConfig(config);
}

async function getUsernameForHWID(hwid) {
    if (!requireUsername) return 'User';
    try {
        const axios = require('axios');
        const res = await axios.get(`https://ntk-x.eu/api/app-name/${hwid}`);
        if (res.data && res.data.success && res.data.name) {
            return res.data.name;
        }
    } catch (e) {}
    const config = loadConfig();
    return config.users[hwid]?.username || 'Anonymous';
}

async function getUsernameAndMessageId(hwid) {
    return { username: await getUsernameForHWID(hwid), messageId: null };
}

function hasUsernameForHWID(hwid) {
    return getUsernameForHWID(hwid).then(username => username !== 'Anonymous');
}

function saveUsernameForHWID(hwid, username) {
    const config = loadConfig();
    if (!config.users[hwid]) {
        config.users[hwid] = {};
    }
    config.users[hwid].username = username;
}



let cachedHWID = null;

function getMachineGuid() {
    try {
        const { execSync } = require('child_process');
        const guid = execSync('powershell -Command "(Get-ItemProperty -Path HKLM:\\SOFTWARE\\Microsoft\\Cryptography).MachineGuid"', { encoding: 'utf8', timeout: 5000 }).trim();
        if (guid && guid.length > 10) {
            return guid;
        }
    } catch (e) {}
    try {
        const { execSync } = require('child_process');
        const regOutput = execSync('reg query HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Cryptography /v MachineGuid', { encoding: 'utf8', timeout: 5000 }).trim();
        const match = regOutput.match(/MachineGuid\\s+REG_SZ\\s+(\\S+)/i);
        if (match && match[1]) {
            return match[1];
        }
    } catch (e) {}
    return null;
}

function getBaseboardSerial() {
    try {
        const { execSync } = require('child_process');
        const timeout = 15000;
        const invalidSerials = [
            'to be filled by o.e.m.', 'not available', 'none', 'default string', 
            '00000000', '000000000000', '123456789', 'not specified', 
            'base board serial number', 'not applicable', 'type2 - board asset tag',
            'system serial number', 'system product name'
        ];
        
        let serial = execSync('powershell -Command "(Get-WmiObject -Class Win32_BaseBoard).SerialNumber"', { encoding: 'utf8', timeout }).trim();
        if (serial && serial !== '' && !invalidSerials.includes(serial.toLowerCase())) {
            return serial;
        }
        const biosSerial = execSync('powershell -Command "(Get-WmiObject -Class Win32_BIOS).SerialNumber"', { encoding: 'utf8', timeout }).trim();
        if (biosSerial && biosSerial !== '' && !invalidSerials.includes(biosSerial.toLowerCase())) {
            return biosSerial;
        }
        const uuid = execSync('powershell -Command "(Get-WmiObject -Class Win32_ComputerSystemProduct).UUID"', { encoding: 'utf8', timeout }).trim();
        if (uuid && uuid !== '' && uuid !== 'FFFFFFFF-FFFF-FFFF-FFFF-FFFFFFFFFFFF' && uuid !== '00000000-0000-0000-0000-000000000000') {
            return uuid;
        }
        return null;
    } catch (e) {
        return null;
    }
}

function generateHWID() {
    if (cachedHWID) return cachedHWID;

    try {
        let hardwareId = getMachineGuid();
        
        if (!hardwareId) {
            hardwareId = getBaseboardSerial();
        }
        
        if (!hardwareId) {
            try {
                const { execSync } = require('child_process');
                hardwareId = execSync('powershell -Command "(Get-WmiObject -Class Win32_Processor).ProcessorId"', { encoding: 'utf8', timeout: 15000 }).trim();
            } catch (e) {}
        }

        if (!hardwareId) {
            try {
                const interfaces = os.networkInterfaces();
                for (const name of Object.keys(interfaces)) {
                    for (const net of interfaces[name]) {
                        if (!net.internal && net.mac && net.mac !== '00:00:00:00:00:00') {
                            hardwareId = net.mac;
                            break;
                        }
                    }
                    if (hardwareId) break;
                }
            } catch (e) {}
        }

        if (!hardwareId) {
            hardwareId = os.hostname() || 'GENERIC-HOST';
        }
        
        const cpu = os.cpus()?.[0]?.model || 'Unknown-CPU';
        const platform = os.platform() || 'win32';

        const rawString = `${hardwareId}-${cpu}-${platform}`;
        
        const hwid = Buffer.from(rawString).toString('base64');
        cachedHWID = hwid.substring(0, 32).replace(/[\/\+=]/g, 'X');
        
        return cachedHWID;
    } catch (e) {
        cachedHWID = 'FALLBACK-' + (os.hostname() || 'HOST').substring(0, 10).toUpperCase() + '-ERROR';
        return cachedHWID;
    }
}


async function checkWhitelist() {
    if (!requireLicense) {
        return { allowed: true, hwid: generateHWID(), package: 'lifetime', expires_at: null };
    }
    return new Promise(async (resolve) => {
        const hwid = generateHWID();

        try {
            const apiRes = await new Promise(res => {
                const req = require('https').get(`https://ntk-x.eu/api/check-hwid/${hwid}`, response => {
                    let data = '';
                    response.on('data', chunk => data += chunk);
                    response.on('end', () => {
                        try { res(JSON.parse(data)); } catch(e) { res({success:false}); }
                    });
                }).on('error', () => res({success:false}));
                req.setTimeout(3000, () => { req.destroy(); res({success:false}); });
            });
            if (apiRes && apiRes.isAuthorized) {
                resolve({ allowed: true, hwid, package: apiRes.package, expires_at: apiRes.expires_at });
                return;
            }
        } catch(e) {}

        resolve({ allowed: false, hwid });
    });
}

