async function updateUserMessagesInChat(hwid, newUsername, oldUsername, event) {
    if (!discordClient) {
        event.reply('update-username-history-res', { success: false, updated: 0, message: 'Discord client not initialized' });
        return;
    }
    
    try {
        const channels = ['hu', 'eng'];
        let totalUpdated = 0;
        const RATE_LIMIT_DELAY = 1000;
        
        for (const lang of channels) {
            const channelId = DISCORD_CONFIG.channels[lang];
            if (!channelId) continue;
            
            try {
                const channel = await discordClient.channels.fetch(channelId);
                if (!channel || !channel.isTextBased()) continue;
                
                let allMessages = [];
                let lastMessageId = null;
                const batchSize = 100;
                
                for (let i = 0; i < 10; i++) {
                    const options = { limit: batchSize };
                    if (lastMessageId) options.before = lastMessageId;
                    
                    const messages = await channel.messages.fetch(options);
                    if (messages.size === 0) break;
                    
                    const messageArray = Array.from(messages.values());
                    allMessages = allMessages.concat(messageArray);
                    lastMessageId = messageArray[messageArray.length - 1].id;
                    
                    if (messages.size < batchSize) break;
                }

                let updatedInChannel = 0;
                for (const msg of allMessages) {
                    if (msg.embeds && msg.embeds.length > 0) {
                        const hwidField = msg.embeds[0].fields?.find(f => f.name === 'HWID');
                        const usernameField = msg.embeds[0].fields?.find(f => f.name === 'Username');
                        
                        if (hwidField && hwidField.value === hwid) {
                            if (updatedInChannel > 0) {
                                await new Promise(resolve => setTimeout(resolve, RATE_LIMIT_DELAY));
                            }
                            
                            try {
                                const { EmbedBuilder } = require('discord.js');
                                const oldEmbed = msg.embeds[0];
                                const newEmbed = new EmbedBuilder()
                                    .setDescription(oldEmbed.description)
                                    .setTimestamp(oldEmbed.timestamp ? new Date(oldEmbed.timestamp) : new Date());
                                
                                if (oldEmbed.color) newEmbed.setColor(oldEmbed.color);
                                
                                const newFields = oldEmbed.fields.map(field => {
                                    if (field.name === 'Username') {
                                        return { name: 'Username', value: newUsername, inline: field.inline };
                                    }
                                    return field;
                                });
                                newEmbed.addFields(newFields);
                                
                                await msg.edit({ embeds: [newEmbed] });
                                totalUpdated++;
                                updatedInChannel++;
                                
                                event.reply('update-username-history-progress', { 
                                    channel: lang, 
                                    updated: updatedInChannel, 
                                    total: totalUpdated 
                                });
                                
                            } catch (editErr) {
                                if (editErr.status === 429) {
                                    const retryAfter = editErr.retryAfter || 5000;
                                    await new Promise(resolve => setTimeout(resolve, retryAfter));
                                    try {
                                        await msg.edit({ embeds: [newEmbed] });
                                        totalUpdated++;
                                        updatedInChannel++;
                                    } catch (retryErr) {
                                    }
                                }
                            }
                        }
                    }
                }
                
            } catch (channelErr) {
            }
        }
        
        event.reply('update-username-history-res', { 
            success: true, 
            updated: totalUpdated, 
            newUsername: newUsername 
        });
        
    } catch (e) {
        event.reply('update-username-history-res', { 
            success: false, 
            updated: 0, 
            message: e.message 
        });
    }
}

