ipcMain.on('get-dm-history', async (event, { token, targetId }) => {
    try {
        const https = require('https');
        
        const createDMOptions = {
            hostname: 'discord.com',
            port: 443,
            path: '/api/v10/users/@me/channels',
            method: 'POST',
            headers: {
                'Authorization': token,
                'Content-Type': 'application/json'
            }
        };
        
        const createDMReq = https.request(createDMOptions, (createDMRes) => {
            let dmData = '';
            createDMRes.on('data', (chunk) => { dmData += chunk; });
            createDMRes.on('end', () => {
                if (createDMRes.statusCode === 200) {
                    try {
                        const dmChannel = JSON.parse(dmData);
                        const channelId = dmChannel.id;
                        
                        const allMessages = [];
                        let lastMessageId = null;
                        const MAX_MESSAGES = 10000;
                        const BATCH_SIZE = 100;
                        
                        const fetchMessages = () => {
                            let path = `/api/v10/channels/${channelId}/messages?limit=${BATCH_SIZE}`;
                            if (lastMessageId) {
                                path += `&before=${lastMessageId}`;
                            }
                            
                            const messagesOptions = {
                                hostname: 'discord.com',
                                port: 443,
                                path: path,
                                method: 'GET',
                                headers: {
                                    'Authorization': token,
                                    'Content-Type': 'application/json'
                                }
                            };
                            
                            const messagesReq = https.request(messagesOptions, (messagesRes) => {
                                let messagesData = '';
                                messagesRes.on('data', (chunk) => { messagesData += chunk; });
                                messagesRes.on('end', () => {
                                    if (messagesRes.statusCode === 200) {
                                        try {
                                            const messages = JSON.parse(messagesData);
                                            
                                            if (messages.length === 0) {
                                                event.reply('dm-history-res', { success: true, messages: allMessages });
                                                return;
                                            }
                                            
                                            allMessages.push(...messages);
                                            
                                            if (allMessages.length >= MAX_MESSAGES) {
                                                event.reply('dm-history-res', { success: true, messages: allMessages.slice(0, MAX_MESSAGES) });
                                                return;
                                            }
                                            
                                            lastMessageId = messages[messages.length - 1].id;
                                            fetchMessages();
                                            
                                        } catch (e) {
                                            event.reply('dm-history-res', { success: false, error: 'Invalid messages JSON response' });
                                        }
                                    } else if (messagesRes.statusCode === 401) {
                                        event.reply('dm-history-res', { success: false, error: 'Unauthorized - Invalid token' });
                                    } else if (messagesRes.statusCode === 403) {
                                        event.reply('dm-history-res', { success: false, error: 'Forbidden - No permission to view this DM' });
                                    } else {
                                        event.reply('dm-history-res', { success: false, status: messagesRes.statusCode, error: messagesData });
                                    }
                                });
                            });
                            
                            messagesReq.on('error', (error) => {
                                event.reply('dm-history-res', { success: false, error: error.message });
                            });
                            
                            messagesReq.end();
                        };
                        
                        fetchMessages();
                    } catch (e) {
                        event.reply('dm-history-res', { success: false, error: 'Invalid DM channel JSON response' });
                    }
                } else if (createDMRes.statusCode === 401) {
                    event.reply('dm-history-res', { success: false, error: 'Unauthorized - Invalid token' });
                } else if (createDMRes.statusCode === 403) {
                    event.reply('dm-history-res', { success: false, error: 'Cannot create DM with this user' });
                } else {
                    event.reply('dm-history-res', { success: false, status: createDMRes.statusCode, error: dmData });
                }
            });
        });
        
        createDMReq.on('error', (error) => {
            event.reply('dm-history-res', { success: false, error: error.message });
        });
        
        createDMReq.write(JSON.stringify({ recipient_id: targetId }));
        createDMReq.end();
        
    } catch (error) {
        event.reply('dm-history-res', { success: false, error: error.message });
    }
});

ipcMain.on('send-dm-message', async (event, { token, targetId, content }) => {
    try {
        const https = require('https');
        
        const createDMOptions = {
            hostname: 'discord.com',
            port: 443,
            path: '/api/v9/users/@me/channels',
            method: 'POST',
            headers: {
                'Authorization': token,
                'Content-Type': 'application/json',
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:109.0) Gecko/20100101 Firefox/109.0'
            }
        };

        const createDMReq = https.request(createDMOptions, (createDMRes) => {
            let dmData = '';
            createDMRes.on('data', (chunk) => { dmData += chunk; });
            createDMRes.on('end', () => {
                if (createDMRes.statusCode === 200) {
                    try {
                        const dmChannel = JSON.parse(dmData);
                        const channelId = dmChannel.id;

                        const sendOptions = {
                            hostname: 'discord.com',
                            port: 443,
                            path: `/api/v9/channels/${channelId}/messages`,
                            method: 'POST',
                            headers: {
                                'Authorization': token,
                                'Content-Type': 'application/json',
                                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:109.0) Gecko/20100101 Firefox/109.0'
                            }
                        };

                        const sendReq = https.request(sendOptions, (sendRes) => {
                            let sendData = '';
                            sendRes.on('data', (chunk) => { sendData += chunk; });
                            sendRes.on('end', () => {
                                if (sendRes.statusCode === 200) {
                                    event.reply('send-dm-message-res', { success: true });
                                } else {
                                    event.reply('send-dm-message-res', { success: false, error: sendData });
                                }
                            });
                        });

                        sendReq.on('error', (error) => {
                            event.reply('send-dm-message-res', { success: false, error: error.message });
                        });

                        sendReq.write(JSON.stringify({ content: content }));
                        sendReq.end();

                    } catch (e) {
                        event.reply('send-dm-message-res', { success: false, error: 'Invalid DM channel JSON response' });
                    }
                } else if (createDMRes.statusCode === 401) {
                    event.reply('send-dm-message-res', { success: false, error: 'Unauthorized - Invalid token' });
                } else {
                    event.reply('send-dm-message-res', { success: false, error: dmData });
                }
            });
        });

        createDMReq.on('error', (error) => {
            event.reply('send-dm-message-res', { success: false, error: error.message });
        });

        createDMReq.write(JSON.stringify({ recipient_id: targetId }));
        createDMReq.end();

    } catch (error) {
        event.reply('send-dm-message-res', { success: false, error: error.message });
    }
});

ipcMain.on('delete-dm-message', async (event, { token, messageId }) => {
    try {
        const https = require('https');
        
        const deleteOptions = {
            hostname: 'discord.com',
            port: 443,
            path: `/api/v9/channels/@me/messages/${messageId}`,
            method: 'DELETE',
            headers: {
                'Authorization': token,
                'Content-Type': 'application/json',
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:109.0) Gecko/20100101 Firefox/109.0'
            }
        };

        const deleteReq = https.request(deleteOptions, (deleteRes) => {
            let deleteData = '';
            deleteRes.on('data', (chunk) => { deleteData += chunk; });
            deleteRes.on('end', () => {
                if (deleteRes.statusCode === 204 || deleteRes.statusCode === 200) {
                    event.reply('delete-dm-message-res', { success: true });
                } else if (deleteRes.statusCode === 403) {
                    event.reply('delete-dm-message-res', { success: false, error: 'Forbidden - Cannot delete this message' });
                } else if (deleteRes.statusCode === 404) {
                    event.reply('delete-dm-message-res', { success: false, error: 'Message not found' });
                } else {
                    event.reply('delete-dm-message-res', { success: false, error: deleteData });
                }
            });
        });

        deleteReq.on('error', (error) => {
            event.reply('delete-dm-message-res', { success: false, error: error.message });
        });

        deleteReq.end();

    } catch (error) {
        event.reply('delete-dm-message-res', { success: false, error: error.message });
    }
});

ipcMain.on('get-discord-friends', async (event, token) => {
    ('=== IPC get-discord-friends called ===');
    ('Token length:', token ? token.length : 0);
    try {
        const https = require('https');
        
        const options = {
            hostname: 'discord.com',
            port: 443,
            path: '/api/v9/users/@me/relationships',
            method: 'GET',
            headers: {
                'Authorization': token,
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:109.0) Gecko/20100101 Firefox/109.0',
                'Accept': '*/*',
                'Accept-Language': 'en-US,en;q=0.5',
                'Referer': 'https://discord.com/channels/@me',
                'X-Discord-Locale': 'en-US',
                'X-Super-Properties': ''
            }
        };
        
        ('Sending request to Discord API...');
        
        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => { data += chunk; });
            res.on('end', () => {
                ('Discord API response status:', res.statusCode);
                if (res.statusCode === 200) {
                    try {
                        const relationships = JSON.parse(data);
                        const friends = relationships.filter(r => r.type === 1).map(r => ({
                            id: r.user.id,
                            username: r.user.username,
                            global_name: r.user.global_name,
                            avatar: r.user.avatar,
                            discriminator: r.user.discriminator
                        }));
                        ('Found friends:', friends.length);
                        event.reply('discord-friends-res', { success: true, friends: friends });
                    } catch (e) {
                        ('Error parsing JSON:', e);
                        event.reply('discord-friends-res', { success: false, error: 'Invalid JSON response' });
                    }
                } else if (res.statusCode === 401) {
                    ('Discord API: Unauthorized');
                    event.reply('discord-friends-res', { success: false, error: 'Unauthorized - Invalid token' });
                } else if (res.statusCode === 403) {
                    ('Discord API: Forbidden');
                    event.reply('discord-friends-res', { success: false, error: 'Forbidden - No permission' });
                } else {
                    ('Discord API error:', res.statusCode, data);
                    event.reply('discord-friends-res', { success: false, status: res.statusCode, error: data });
                }
            });
        });
        
        req.on('error', (error) => {
            ('Request error:', error);
            event.reply('discord-friends-res', { success: false, error: error.message });
        });
        
        req.end();
        
    } catch (error) {
        ('IPC handler error:', error);
        event.reply('discord-friends-res', { success: false, error: error.message });
    }
});

