const gotTheLock = app.requestSingleInstanceLock();

if (!gotTheLock) {
    app.quit();
} else {
    app.on('second-instance', () => {
        if (splashWin) {
            if (splashWin.isMinimized()) splashWin.restore();
            splashWin.focus();
        } else if (mainWin) {
            if (mainWin.isMinimized()) mainWin.restore();
            mainWin.focus();
        }
    });

    app.whenReady().then(async () => {
    app.whenReady().then(async () => {
        await createSplashWindow();
        const { session } = require('electron');
        session.fromPartition('memory').webRequest.onHeadersReceived((details, callback) => {
            if (!details || !details.responseHeaders) return callback({ cancel: false });
            const lowerHeaders = {};
            for (const key in details.responseHeaders) { lowerHeaders[key.toLowerCase()] = details.responseHeaders[key]; }
            delete lowerHeaders['x-frame-options'];
            delete lowerHeaders['content-security-policy'];
            callback({ cancel: false, responseHeaders: lowerHeaders });
        });
        await initDiscordBot();
        await initNameRegistrationBot();
            const hwid = generateHWID();
            const username = await getUsernameForHWID(hwid);
            await addOnlineUser(hwid, username);

            const pingServer = () => {
                const req = require('https').request({
                    hostname: 'ntk-x.eu',
                    port: 443,
                    path: '/api/ping',
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' }
                }, res => {
                    res.on('data', () => {});
                });
                req.on('error', () => {});
                req.write(JSON.stringify({ hwid, version: CURRENT_VERSION }));
                req.end();
            };
            pingServer();
            setInterval(pingServer, 30000);
        }, 5000);
    });
}

