ipcMain.on('window-action', async (event, action) => {
    const win = BrowserWindow.getFocusedWindow();
    if (!win) return;
    if (action === 'close') {
        const hwid = generateHWID();
        await removeOnlineUser(hwid);
        if (!win.isDestroyed()) {
            win.close();
        }
    }
    else if (action === 'minimize') {
        if (!win.isDestroyed()) win.minimize();
    }
    else if (action === 'maximize') {
        if (!win.isDestroyed()) {
            if (win.isMaximized()) win.unmaximize();
            else win.maximize();
        }
    }
});

ipcMain.on('get-ip-info', (event) => {
    let localIp = 'N/A';
    try {
        const interfaces = os.networkInterfaces();
        for (const name of Object.keys(interfaces)) {
            for (const netInf of interfaces[name]) {
                if (netInf.family === 'IPv4' && !netInf.internal) {
                    localIp = netInf.address;
                    break;
                }
            }
        }
    } catch (e) { }
    https.get('https://api.ipify.org?format=json', (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
            try {
                const publicIp = JSON.parse(data).ip;
                event.reply('ip-info-res', { localIp, publicIp });
            } catch (e) { event.reply('ip-info-res', { localIp, publicIp: 'Failed' }); }
        });
    }).on('error', () => event.reply('ip-info-res', { localIp, publicIp: 'Offline' }));
});

ipcMain.on('run-port-scan', (event, targetHost) => {
    const ports = [20, 21, 22, 23, 25, 53, 67, 68, 69, 80, 110, 119, 123, 135, 137, 138, 139, 143, 161, 162, 389, 443, 445, 465, 514, 587, 636, 993, 995, 1080, 1433, 1521, 1723, 3306, 3389, 5432, 5900, 8080, 8443];
    let completed = 0;
    const results = [];
    ports.forEach(port => {
        const socket = new net.Socket();
        socket.setTimeout(800);
        socket.on('connect', () => { results.push({ port, status: 'OPEN' }); socket.destroy(); checkDone(); });
        socket.on('timeout', () => { results.push({ port, status: 'CLOSED' }); socket.destroy(); checkDone(); });
        socket.on('error', () => { results.push({ port, status: 'CLOSED' }); checkDone(); });
        socket.connect(port, targetHost);
    });
    function checkDone() { completed++; if (completed === ports.length) event.reply('port-scan-res', { results }); }
});

