ipcMain.on('fetch-latest-screen', async (event, data) => {
    if (!discordViewerBot) {
        event.reply('screen-update', { image: null });
        return;
    }

    try {
        const channel = await discordViewerBot.channels.fetch(data.channelId);
        if (!channel || !channel.isTextBased()) {
            event.reply('screen-update', { image: null });
            return;
        }

        const messages = await channel.messages.fetch({ limit: 10 });
        const imageMessage = messages.find(msg => msg.attachments.size > 0);
        
        if (imageMessage && imageMessage.attachments.first()) {
            const attachment = imageMessage.attachments.first();
            if (attachment.contentType && attachment.contentType.startsWith('image/')) {
                const response = await fetch(attachment.url);
                const buffer = await response.arrayBuffer();
                const base64 = Buffer.from(buffer).toString('base64');
                event.reply('screen-update', { image: base64 });
            } else {
                event.reply('screen-update', { image: null });
            }
        } else {
            event.reply('screen-update', { image: null });
        }
    } catch (error) {
        console.error('Failed to fetch screen:', error);
        event.reply('screen-update', { image: null });
    }
});

