ipcMain.on('run-tiktok-osint', (event, username) => {
    const url = `https://www.tiktok.com/@${username}`;
    const options = {
        headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
            'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8',
            'Accept-Language': 'hu-HU,hu;q=0.9,en-US;q=0.8,en;q=0.7',
            'Cache-Control': 'no-cache',
            'Pragma': 'no-cache',
            'Sec-Ch-Ua': '"Chromium";v="122", "Not(A:Brand";v="24", "Google Chrome";v="122"',
            'Sec-Ch-Ua-Mobile': '?0',
            'Sec-Ch-Ua-Platform': '"Windows"',
            'Sec-Fetch-Dest': 'document',
            'Sec-Fetch-Mode': 'navigate',
            'Sec-Fetch-Site': 'none',
            'Sec-Fetch-User': '?1',
            'Upgrade-Insecure-Requests': '1'
        }
    };

    https.get(url, options, (res) => {
        if (res.statusCode === 301 || res.statusCode === 302) {
            const newUrl = res.headers.location.startsWith('http') ? res.headers.location : `https://www.tiktok.com${res.headers.location}`;
            https.get(newUrl, options, (res2) => {
                let data = '';
                res2.on('data', chunk => data += chunk);
                res2.on('end', () => processTikTokHTML(data, event, username));
            }).on('error', (e) => event.reply('tiktok-osint-res', { success: false, msg: 'Redirect hiba: ' + e.message }));
            return;
        }

        if (res.statusCode !== 200) {
            event.reply('tiktok-osint-res', { success: false, msg: `Hiba: TikTok szerver válasza ${res.statusCode}. Próbáld meg később vagy ellenőrizd a nevet.` });
            return;
        }

        let data = '';
        res.on('data', chunk => { if (data.length < 5000000) data += chunk; });
        res.on('end', () => processTikTokHTML(data, event, username));
    }).on('error', (e) => event.reply('tiktok-osint-res', { success: false, msg: 'Hálózati hiba: ' + e.message }));
});

