let pingProcess = null;
let tcpPingInterval = null;

ipcMain.on('run-ping-tool', (event, target) => {
    if (pingProcess) { pingProcess.kill(); pingProcess = null; }
    if (tcpPingInterval) { clearInterval(tcpPingInterval); tcpPingInterval = null; }

    const parts = target.replace(/^[a-z]+:\/\//i, '').split('/')[0].split(':');
    const host = parts[0];
    const port = parts[1];

    if (port) {
        event.reply('ping-res-raw', { msg: `[*] Starting TCP ping to ${host} on port ${port}...`, color: "var(--accent)" });
        
        const runTcpPing = () => {
            const start = Date.now();
            const socket = new net.Socket();
            socket.setTimeout(2000);
            
            socket.connect(port, host, () => {
                const time = Date.now() - start;
                event.reply('ping-res-raw', { msg: `Connected to ${host}:${port}: time=${time}ms protocol=TCP`, color: "#00ff9d" });
                socket.destroy();
            });

            socket.on('error', (err) => {
                event.reply('ping-res-raw', { msg: `Connection failed to ${host}:${port} (${err.code})`, color: "#ff4444" });
                socket.destroy();
            });

            socket.on('timeout', () => {
                event.reply('ping-res-raw', { msg: `Connection timed out on ${host}:${port}`, color: "#ff4444" });
                socket.destroy();
            });
        };

        runTcpPing();
        tcpPingInterval = setInterval(runTcpPing, 1000);
    } else {
        const isWindows = process.platform === 'win32';
        const pingArgs = isWindows ? ['-t', host] : [host];
        pingProcess = spawn('ping', pingArgs);

        pingProcess.stdout.on('data', (data) => {
            const output = data.toString('utf-8');
            const lines = output.split('\n').filter(l => l.trim().length > 0);
            lines.forEach(line => {
                let color = "var(--accent)";
                if (line.toLowerCase().match(/time=|idő=|ms|ttl=/)) color = "#00ff9d";
                if (line.toLowerCase().match(/timed out|időtúllépés|unreachable|not found/)) color = "#ff4444";
                event.reply('ping-res-raw', { msg: line.trim(), color: color });
            });
        });

        pingProcess.on('error', (err) => {
            event.reply('ping-res-raw', { msg: "Hiba: " + err.message, color: "#ff4444" });
        });
    }
});

ipcMain.on('stop-ping-tool', () => {
    if (pingProcess) { pingProcess.kill(); pingProcess = null; }
    if (tcpPingInterval) { clearInterval(tcpPingInterval); tcpPingInterval = null; }
});

let ddosWorkers = [];
let serverStatusInterval = null;

function parseTarget(target) {
    const url = require('url');
    const dns = require('dns');
    const net = require('net');
    
    try {
        if (target.startsWith('http://') || target.startsWith('https://')) {
            const parsed = url.parse(target);
            return {
                hostname: parsed.hostname,
                port: parsed.port || (parsed.protocol === 'https:' ? '443' : '80'),
                originalTarget: target
            };
        } else {

            if (net.isIP(target)) {
                return {
                    hostname: target,
                    port: null,
                    originalTarget: target,
                    isIP: true
                };
            } else {
                return {
                    hostname: target,
                    port: null,
                    originalTarget: target,
                    isIP: false
                };
            }
        }
    } catch (error) {
        return {
            hostname: target,
            port: null,
            originalTarget: target
        };
    }
}

async function resolveHostname(hostname) {
    const dns = require('dns');
    const net = require('net');
    
    return new Promise((resolve, reject) => {
        if (net.isIP(hostname)) {
            resolve({
                hostname: hostname,
                ip: hostname,
                isIP: true
            });
            return;
        }

        dns.lookup(hostname, (err, address, family) => {
            if (err) {
                reject(err);
                return;
            }
            
            resolve({
                hostname: hostname,
                ip: address,
                family: family,
                isIP: false
            });
        });
    });
}

async function scanPorts(hostname) {
    const net = require('net');
    const commonPorts = [21, 22, 23, 25, 53, 80, 110, 143, 443, 993, 995, 8080, 8443, 3306, 5432];
    const openPorts = [];
    
    return new Promise((resolve) => {
        let checked = 0;
        
        commonPorts.forEach(port => {
            const socket = new net.Socket();
            socket.setTimeout(2000);
            
            socket.connect(port, hostname, () => {
                openPorts.push(port);
                socket.destroy();
            });
            
            socket.on('error', () => {
                socket.destroy();
            });
            
            socket.on('timeout', () => {
                socket.destroy();
            });
            
            socket.on('close', () => {
                checked++;
                if (checked === commonPorts.length) {
                    resolve(openPorts.sort((a, b) => a - b));
                }
            });
        });
    });
}


function measurePing(ip, port) {
    return new Promise((resolve) => {
        const socket = new net.Socket();
        const startTime = Date.now();
        socket.setTimeout(3000);
        socket.on('connect', () => {
            const ping = Date.now() - startTime;
            socket.destroy();
            resolve(ping + 'ms');
        });
        socket.on('timeout', () => {
            socket.destroy();
            resolve('timeout');
        });
        socket.on('error', (err) => {
            socket.destroy();
            if (err.code === 'ECONNREFUSED') {
                resolve('blokkolt');
            } else if (err.code === 'ETIMEDOUT' || err.code === 'ENOTFOUND') {
                resolve('offline');
            } else {
                resolve('túlterhelt');
            }
        });
        socket.connect(port, ip);
    });
}

function getFiveMServerInfo(code) {
    return new Promise((resolve, reject) => {
        const options = {
            method: 'GET',
            headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36' }
        };
        const req = https.request(`https://cfx.re/join/${code}`, options, (res) => {
            let targetUrl = res.headers['x-citizenfx-url'] || res.headers['location'];
            if (!targetUrl) return reject(new Error('Invalid server code or hidden endpoint'));
            if (!targetUrl.endsWith('/')) targetUrl += '/';
            const reqModule = targetUrl.startsWith('https') ? https : require('http');
            reqModule.get(`${targetUrl}info.json`, { timeout: 10000 }, (infoRes) => {
                let infoData = '';
                infoRes.on('data', chunk => infoData += chunk);
                infoRes.on('end', () => {
                    try {
                        const json = JSON.parse(infoData);
                        json.connectEndPoints = [targetUrl.replace(/^https?:\/\//, '').replace(/\/$/, '')];
                        json.sv_maxclients = json.vars?.sv_maxClients || 0;
                        json.hostname = json.vars?.sv_projectName || json.vars?.sv_hostname || 'Unknown Server';
                        
                        reqModule.get(`${targetUrl}dynamic.json`, { timeout: 10000 }, (dynRes) => {
                            let dynData = '';
                            dynRes.on('data', chunk => dynData += chunk);
                            dynRes.on('end', () => {
                                try {
                                    const dynJson = JSON.parse(dynData);
                                    json.clients = dynJson.clients || 0;
                                } catch(e) {}
                                resolve(json);
                            });
                        }).on('error', () => resolve(json));
                    } catch(e) { reject(e); }
                });
            }).on('error', reject);
        }).on('error', reject);
        req.end();
    });
}

ipcMain.on('resolve-fivem-server', async (event, input, autoRefresh = false) => {
    try {
        const parsed = parseFiveMTarget(input);
        
        let cfxCode = null;
        const urlMatch = input.match(/cfx\.re\/join\/([a-zA-Z0-9]{5,6})/i);
        const plainMatch = input.match(/^([a-zA-Z0-9]{5,6})$/);
        
        if (urlMatch) {
            cfxCode = urlMatch[1];
        } else if (plainMatch) {
            cfxCode = plainMatch[1];
        }
        
        if (cfxCode && !parsed.ip) {
            try {
                const serverData = await getFiveMServerInfo(cfxCode);
                if (serverData && serverData.connectEndPoints && serverData.connectEndPoints.length > 0) {
                    const endpoint = serverData.connectEndPoints[0];
                    const epMatch = endpoint.match(/([\d.]+):(\d+)/);
                    if (epMatch) {
                        const ip = epMatch[1];
                        const port = parseInt(epMatch[2]);
                        const [port40120, ping] = await Promise.all([
                            checkSinglePort(ip, 40120),
                            measurePing(ip, port)
                        ]);
                        event.reply('fivem-resolve-res', {
                            success: true,
                            autoRefresh: autoRefresh,
                            name: serverData.hostname || 'Unknown Server',
                            players: serverData.clients || 0,
                            maxPlayers: serverData.sv_maxclients || 0,
                            provider: detectProvider(ip),
                            port40120: port40120,
                            ping: ping,
                            endpoint: endpoint,
                            ip: ip,
                            port: port
                        });
                        return;
                    }
                }
            } catch (e) {

            }
        }
        
        let ip = parsed.ip;
        let hostname = parsed.hostname;
        
        if (parsed.isDomain) {
            try {
                const resolved = await resolveFiveMHostname(parsed.hostname);
                ip = resolved.ip;
                hostname = resolved.hostname;
            } catch (err) {
                event.reply('fivem-resolve-res', {
                    success: false,
                    autoRefresh: autoRefresh,
                    error: `Failed to resolve hostname: ${err.message}`
                });
                return;
            }
        }
        
        const port40120 = await checkSinglePort(ip, 40120);
        const ping = await measurePing(ip, parsed.port);
        
        event.reply('fivem-resolve-res', {
            success: true,
            autoRefresh: autoRefresh,
            name: hostname,
            players: '?',
            maxPlayers: '?',
            provider: detectProvider(ip),
            port40120: port40120,
            ping: ping,
            endpoint: `${ip}:${parsed.port}`,
            ip: ip,
            port: parsed.port
        });
        
    } catch (error) {
        event.reply('fivem-resolve-res', {
            success: false,
            error: error.message
        });
    }
});


ipcMain.on('fivem-spoof-start', async (event) => {
    try {
        const { execSync, spawn } = require('child_process');
        const fs = require('fs');
        const path = require('path');
        const os = require('os');
        
        const results = [];
        const errors = [];
        
        const newHWID = require('crypto').randomUUID().replace(/-/g, '').substring(0, 32);
        const newMachineGuid = require('crypto').randomUUID();
        results.push(`Generated new HWID: ${newHWID}`);
        
        const deleteRegistryKey = (keyPath) => {
            try {
                execSync(`reg delete "${keyPath}" /f`, { windowsHide: true, stdio: 'pipe' });
                results.push(`Removed registry: ${keyPath}`);
                return true;
            } catch (e) {
                return false;
            }
        };
        
        const setRegistryValue = (keyPath, name, value, type = 'REG_SZ') => {
            try {
                try {
                    execSync(`reg add "${keyPath}" /f`, { windowsHide: true, stdio: 'pipe' });
                } catch (e) {}
                execSync(`reg add "${keyPath}" /v "${name}" /t ${type} /d "${value}" /f`, { 
                    windowsHide: true, 
                    stdio: 'pipe' 
                });
                return true;
            } catch (e) {
                errors.push(`Registry error for ${keyPath}/${name}: ${e.message}`);
                return false;
            }
        };
        
        const registryPaths = [
            'HKCU\\Software\\FiveM',
            'HKCU\\Software\\Cfx.re',
            'HKCU\\Software\\CitizenFX',
            'HKLM\\SOFTWARE\\WOW6432Node\\FiveM',
            'HKLM\\SOFTWARE\\WOW6432Node\\Cfx.re',
            'HKLM\\SOFTWARE\\FiveM',
            'HKLM\\SOFTWARE\\Cfx.re'
        ];
        
        for (const regPath of registryPaths) {
            deleteRegistryKey(regPath);
        }
        
        if (setRegistryValue('HKLM\\SOFTWARE\\Microsoft\\Cryptography', 'MachineGuid', newMachineGuid)) {
            results.push(`Spoofed MachineGuid to: ${newMachineGuid}`);
        }
        
        const newProductId = `${Math.floor(10000 + Math.random() * 89999)}-OEM-${Math.floor(1000000 + Math.random() * 8999999)}-${Math.floor(10000 + Math.random() * 89999)}`;
        if (setRegistryValue('HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion', 'ProductId', newProductId)) {
            results.push('Spoofed ProductId');
        }
        
        const newInstallDate = Math.floor(Date.now() / 1000) - Math.floor(Math.random() * 31536000);
        if (setRegistryValue('HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion', 'InstallDate', newInstallDate.toString(), 'REG_DWORD')) {
            results.push('Spoofed InstallDate');
        }

        if (setRegistryValue('HKCU\\Software\\FiveM', 'PlayerId', newHWID)) {
            setRegistryValue('HKCU\\Software\\FiveM', 'SessionId', require('crypto').randomUUID());
            results.push('Created new FiveM identifiers');
        }

        const cleanupPaths = [
            path.join(os.homedir(), 'AppData', 'Local', 'FiveM'),
            path.join(os.homedir(), 'AppData', 'Roaming', 'CitizenFX'),
            path.join(os.homedir(), 'AppData', 'Roaming', 'FiveM'),
            path.join(os.tmpdir(), 'FiveM'),
            path.join(os.homedir(), 'AppData', 'Local', 'CrashDumps'),
            path.join(os.homedir(), 'AppData', 'Local', 'DigitalEntitlements')
        ];
        
        for (const cleanupPath of cleanupPaths) {
            try {
                if (fs.existsSync(cleanupPath)) {
                    fs.rmSync(cleanupPath, { recursive: true, force: true });
                    results.push(`Cleaned: ${cleanupPath}`);
                }
            } catch (e) {

            }
        }
        
        try {
            const tempFiles = fs.readdirSync(os.tmpdir());
            for (const file of tempFiles) {
                if (file.startsWith('FiveM') || file.startsWith('Cfx') || file.startsWith('CitizenFX')) {
                    try {
                        fs.rmSync(path.join(os.tmpdir(), file), { recursive: true, force: true });
                    } catch (e) {}
                }
            }
            results.push('Cleared temp files');
        } catch (e) {}
        
        try {
            const gtaSettings = path.join(os.homedir(), 'Documents', 'Rockstar Games', 'GTA V', 'profiles');
            if (fs.existsSync(gtaSettings)) {
                const deleteDatCfgFiles = (dir) => {
                    const entries = fs.readdirSync(dir, { withFileTypes: true });
                    for (const entry of entries) {
                        const fullPath = path.join(dir, entry.name);
                        if (entry.isDirectory()) {
                            deleteDatCfgFiles(fullPath);
                        } else if (entry.name.endsWith('.dat') || entry.name.endsWith('.cfg')) {
                            try {
                                fs.unlinkSync(fullPath);
                            } catch (e) {}
                        }
                    }
                };
                deleteDatCfgFiles(gtaSettings);
                results.push('Cleaned GTA5 profile settings');
            }
        } catch (e) {}

        try {
            execSync('ipconfig /flushdns', { windowsHide: true, stdio: 'pipe' });
            results.push('Flushed DNS cache');
        } catch (e) {}
        
        event.reply('fivem-spoof-res', { 
            success: true, 
            msg: 'FiveM spoofing complete! Registry cleaned, new HWID generated, files removed.',
            details: results
        });
        
    } catch (error) {
        event.reply('fivem-spoof-res', { 
            success: false, 
            error: error.message,
            needsAdmin: error.message.includes('ACCESS') || error.message.includes('admin') 
        });
    }
});

ipcMain.on('fivem-spoof-stop', (event) => {
    try {
        const { execSync } = require('child_process');
        const fs = require('fs');
        const path = require('path');
        const os = require('os');
        
        const results = [];
        
        try {
            execSync('reg delete "HKCU\\Software\\FiveM" /f', { 
                windowsHide: true, 
                stdio: 'pipe' 
            });
            results.push('Removed HKCU\\Software\\FiveM');
        } catch (e) {
        }

        const otherKeys = [
            'HKCU\\Software\\Cfx.re',
            'HKCU\\Software\\CitizenFX'
        ];
        
        for (const key of otherKeys) {
            try {
                execSync(`reg delete "${key}" /f`, { windowsHide: true, stdio: 'pipe' });
                results.push(`Removed ${key}`);
            } catch (e) {}
        }
        
        try {
            const logPath = path.join(os.tmpdir(), 'fivem_restore.log');
            fs.writeFileSync(logPath, 'Restored to default state\n' + results.join('\n'));
        } catch (e) {}
        
        event.reply('fivem-spoof-res', { 
            success: true, 
            msg: 'FiveM spoofing stopped. Registry restored.',
            details: results
        });
        
    } catch (error) {
        event.reply('fivem-spoof-res', { 
            success: false, 
            error: error.message 
        });
    }
});

