function processTikTokHTML(data, event, username) {
    try {
        const videoData = [];
        const seenIds = new Set();

        const scriptTag = data.match(/<script id="__UNIVERSAL_DATA_FOR_REHYDRATION__" [^>]*>(.*?)<\/script>/s);
        if (scriptTag && scriptTag[1]) {
            try {
                const jsonData = JSON.parse(scriptTag[1]);

                let items = null;
                if (jsonData.__DEFAULT_SCOPE__?.['webapp.user-detail']?.itemList) {
                    items = jsonData.__DEFAULT_SCOPE__['webapp.user-detail'].itemList;
                } else if (jsonData.__DEFAULT_SCOPE__?.['webapp.user-detail']?.itemModule) {
                    items = Object.values(jsonData.__DEFAULT_SCOPE__['webapp.user-detail'].itemModule);
                } else if (jsonData.__DEFAULT_SCOPE__?.itemModule) {
                    items = Object.values(jsonData.__DEFAULT_SCOPE__.itemModule);
                } else if (jsonData.itemModule) {
                    items = Object.values(jsonData.itemModule);
                }

                if (items && Array.isArray(items)) {
                    for (const item of items) {
                        if (item && item.id && !seenIds.has(item.id)) {
                            if (item.video || item.videoInfo) {
                                seenIds.add(item.id);
                                const shareUrl = item.video?.shareUrl || item.videoInfo?.shareUrl || "";
                                const videoUrl = shareUrl || `https://www.tiktok.com/@${username}/video/${item.id}?is_from_webapp=1&sender_device=pc`;
                                videoData.push({
                                    id: item.id,
                                    link: videoUrl,
                                    embedUrl: `https://www.tiktok.com/embed/${item.id}`,
                                    desc: item.desc || item.text || `Video`,
                                    thumb: item.video?.cover || item.video?.dynamicCover || item.video?.originCover || item.videoInfo?.cover || ""
                                });
                            }
                        }
                    }
                }
            } catch (e) { ("JSON parse error", e); }
        }

        const videoUrlMatches = data.matchAll(/\/video\/(\d{18,20})/g);
        for (const match of videoUrlMatches) {
            const id = match[1];
            if (!seenIds.has(id)) {
                let thumb = "";
                const thumbMatch = data.match(new RegExp(`"${id}"[^}]*?"cover":"([^"]+)"`, 'i'));
                if (thumbMatch) {
                    thumb = thumbMatch[1].replace(/\\u002F/g, '/').replace(/\\/g, '');
                }

                seenIds.add(id);
                videoData.push({
                    id: id,
                    link: `https://www.tiktok.com/@${username}/video/${id}?is_from_webapp=1&sender_device=pc`,
                    embedUrl: `https://www.tiktok.com/embed/${id}`,
                    desc: `Video`,
                    thumb: thumb
                });
            }
        }

        const allIds = data.match(/\d{19}/g) || [];
        for (const id of allIds) {
            if (!seenIds.has(id) && (id.startsWith('7') || id.startsWith('1'))) {
                seenIds.add(id);
                videoData.push({
                    id: id,
                    link: `https://www.tiktok.com/@${username}/video/${id}?is_from_webapp=1&sender_device=pc`,
                    embedUrl: `https://www.tiktok.com/embed/${id}`,
                    desc: `Video`,
                    thumb: ""
                });
            }
        }

        const followerCount = (data.match(/"followerCount":(\d+)/) || [0, 'N/A'])[1];
        const followingCount = (data.match(/"followingCount":(\d+)/) || [0, 'N/A'])[1];
        const heartCount = (data.match(/"heartCount":(\d+)/) || [0, 'N/A'])[1];
        const videoCount = (data.match(/"videoCount":(\d+)/) || [0, 'N/A'])[1];
        const nickname = (data.match(/"nickname":"([^"]*)"/) || [0, username])[1];
        const signature = (data.match(/"signature":"([^"]*)"/) || [0, ''])[1];

        if (videoData.length === 0) {
            const allNumbers = data.match(/[71]\d{18}/g) || [];
            for (const id of allNumbers) {
                if (!seenIds.has(id)) {
                    seenIds.add(id);
                    videoData.push({
                        id: id,
                        link: `https://www.tiktok.com/@${username}/video/${id}?is_from_webapp=1&sender_device=pc`,
                        embedUrl: `https://www.tiktok.com/embed/${id}`,
                        desc: `Video`,
                        thumb: ""
                    });
                }
            }
        }

        const itemListPatterns = [
            /"itemList":\s*(\[.*?\])/s,
            /"items":\s*(\[.*?\])/s,
            /window\._SSR_HYDRATED_DATA.*?=.*?({.*?});/s
        ];

        for (const pattern of itemListPatterns) {
            if (videoData.length > 0) break;
            const match = data.match(pattern);
            if (match) {
                try {
                    const parsed = JSON.parse(match[1]);
                    const items = Array.isArray(parsed) ? parsed : (parsed.itemList || parsed.items || []);
                    for (const item of items) {
                        if (item && item.id && !seenIds.has(item.id)) {
                            seenIds.add(item.id);
                            videoData.push({
                                id: item.id,
                                link: `https://www.tiktok.com/@${username}/video/${item.id}?is_from_webapp=1&sender_device=pc`,
                                embedUrl: `https://www.tiktok.com/embed/${item.id}`,
                                desc: item.desc || item.text || `Video`,
                                thumb: item.video?.cover || item.cover || ""
                            });
                        }
                    }
                } catch (e) { }
            }
        }

        if (videoData.length === 0) {
            const aggressiveMatch = data.match(/\d{19}/g);
            if (aggressiveMatch) {
                const uniqueIds = [...new Set(aggressiveMatch)].slice(0, 57);
                for (const id of uniqueIds) {
                    if (!seenIds.has(id)) {
                        seenIds.add(id);
                        videoData.push({
                            id: id,
                            link: `https://www.tiktok.com/@${username}/video/${id}?is_from_webapp=1&sender_device=pc`,
                            embedUrl: `https://www.tiktok.com/embed/${id}`,
                            desc: `Video`,
                            thumb: ""
                        });
                    }
                }
            }
        }

        if (videoData.length === 0 && followerCount !== 'N/A') {
            fetchUserVideosFromAlternativeSource(username, event);
            return;
        }
        if (videoData.length > 0 || followerCount !== 'N/A') {
            event.reply('tiktok-osint-res', {
                success: true,
                stats: { followerCount, followingCount, heartCount, videoCount },
                user: { nickname, signature },
                videos: videoData
            });
        } else {
            event.reply('tiktok-osint-res', { success: false, msg: `No videos found. Found videos: ${videoData.length}, Profile data: ${followerCount !== 'N/A' ? 'OK' : 'N/A'}` });
        }
    } catch (e) {
        event.reply('tiktok-osint-res', { success: false, msg: 'Error: ' + e.message });
    }
}

function fetchUserVideosFromAlternativeSource(username, event) {
    const apiUrl = `https://www.tiktok.com/api/user/detail/?uniqueId=${username}&language=hu`;
    const options = {
        headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
            'Accept': 'application/json, text/plain, */*',
            'Accept-Language': 'hu-HU,hu;q=0.9,en-US;q=0.8,en;q=0.7',
            'Referer': `https://www.tiktok.com/@${username}`,
            'Sec-Ch-Ua': '"Chromium";v="122", "Not(A:Brand";v="24", "Google Chrome";v="122"',
            'Sec-Ch-Ua-Mobile': '?0',
            'Sec-Ch-Ua-Platform': '"Windows"',
            'Sec-Fetch-Dest': 'empty',
            'Sec-Fetch-Mode': 'cors',
            'Sec-Fetch-Site': 'same-origin'
        }
    };

    https.get(apiUrl, options, (res) => {
        let data = '';
        res.on('data', chunk => { if (data.length < 2000000) data += chunk; });
        res.on('end', () => {
            try {
                const jsonData = JSON.parse(data);
                const videoData = [];
                const seenIds = new Set();

                const userInfo = jsonData?.userInfo?.user || {};
                const stats = jsonData?.userInfo?.stats || {};

                const items = jsonData?.itemList || [];
                for (const item of items) {
                    if (item.id && !seenIds.has(item.id)) {
                        seenIds.add(item.id);
                        videoData.push({
                            id: item.id,
                            link: `https://www.tiktok.com/@${username}/video/${item.id}?is_from_webapp=1&sender_device=pc`,
                            embedUrl: `https://www.tiktok.com/embed/${item.id}`,
                            desc: item.desc || `Video`,
                            thumb: item.video?.cover || ""
                        });
                    }
                }

                if (videoData.length > 0 || stats.videoCount) {
                    event.reply('tiktok-osint-res', {
                        success: true,
                        stats: {
                            followerCount: stats.followerCount || 'N/A',
                            followingCount: stats.followingCount || 'N/A',
                            heartCount: stats.heartCount || 'N/A',
                            videoCount: stats.videoCount || 'N/A'
                        },
                        user: {
                            nickname: userInfo.nickname || username,
                            signature: userInfo.signature || ''
                        },
                        videos: videoData
                    });
                } else {
                    event.reply('tiktok-osint-res', {
                        success: false,
                        msg: `No videos found. API response does not contain videos. Found: ${videoData.length}`
                    });
                }
            } catch (e) {
                event.reply('tiktok-osint-res', {
                    success: false,
                    msg: 'API error: ' + e.message
                });
            }
        });
    }).on('error', (e) => {
        event.reply('tiktok-osint-res', {
            success: false,
            msg: 'Alternative query failed: ' + e.message
        });
    });
}

ipcMain.on('run-instagram-osint', (event, username) => {
    const url = `https://www.instagram.com/${username}/`;
    const options = {
        headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
            'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
            'Accept-Language': 'en-US,en;q=0.9',
            'Cache-Control': 'no-cache',
            'Pragma': 'no-cache',
            'Sec-Ch-Ua': '"Chromium";v="122", "Not(A:Brand";v="24", "Google Chrome";v="122"',
            'Sec-Ch-Ua-Mobile': '?0',
            'Sec-Ch-Ua-Platform': '"Windows"',
            'Sec-Fetch-Dest': 'document',
            'Sec-Fetch-Mode': 'navigate',
            'Sec-Fetch-Site': 'none',
            'Sec-Fetch-User': '?1',
            'Upgrade-Insecure-Requests': '1'
        }
    };

    https.get(url, options, (res) => {
        let data = '';
        res.on('data', chunk => { if (data.length < 3000000) data += chunk; });
        res.on('end', () => {
            try {
                let meta = {
                    followers: 'N/A',
                    following: 'N/A',
                    posts: 'N/A',
                    isPrivate: 'Unknown',
                    bio: 'Nincs bio',
                    fullName: username,
                    postsList: []
                };

                const sharedDataMatch = data.match(/window\._sharedData\s*=\s*({.+?});<\/script>/);
                if (sharedDataMatch) {
                    try {
                        const sharedData = JSON.parse(sharedDataMatch[1]);
                        const user = sharedData?.entry_data?.ProfilePage?.[0]?.graphql?.user;
                        if (user) {
                            meta.followers = user.edge_followed_by?.count?.toString() || 'N/A';
                            meta.following = user.edge_follow?.count?.toString() || 'N/A';
                            meta.posts = user.edge_owner_to_timeline_media?.count?.toString() || 'N/A';
                            meta.isPrivate = user.is_private ? 'Yes' : 'No';
                            meta.bio = user.biography || 'Nincs bio';
                            meta.fullName = user.full_name || username;

                            let edges = [];
                            const timelineMedia = user.edge_owner_to_timeline_media || user.timeline_media;
                            if (timelineMedia) {
                                edges = timelineMedia.edges || [];
                            }

                            if (edges.length === 0 && user.media && user.media.nodes) {
                                edges = user.media.nodes.map(node => ({ node }));
                            }

                            meta.postsList = edges.slice(0, 12).map(edge => {
                                const node = edge.node;
                                return {
                                    id: node.id,
                                    shortcode: node.shortcode,
                                    url: `https://www.instagram.com/p/${node.shortcode}/`,
                                    thumb: node.thumbnail_src || node.display_url || (node.thumbnail_resources && node.thumbnail_resources[0]?.src),
                                    likes: node.edge_liked_by?.count || node.like_count || 0,
                                    comments: node.edge_media_to_comment?.count || node.comment_count || 0,
                                    caption: node.edge_media_to_caption?.edges?.[0]?.node?.text || node.caption?.text || '',
                                    isVideo: node.is_video || false
                                };
                            });
                        }
                    } catch (e) {
                    }
                }

                if (meta.followers === 'N/A') {
                    const ogDesc = data.match(/property="og:description" content="([^"]+)"/);
                    if (ogDesc) {
                        const desc = ogDesc[1];
                        const followersMatch = desc.match(/([\d,]+)\s*followers?/i);
                        const followingMatch = desc.match(/([\d,]+)\s*following/i);
                        const postsMatch = desc.match(/([\d,]+)\s*posts?/i);

                        meta.followers = followersMatch ? followersMatch[1] : 'N/A';
                        meta.following = followingMatch ? followingMatch[1] : 'N/A';
                        meta.posts = postsMatch ? postsMatch[1] : 'N/A';
                        if (meta.followers !== 'N/A') {
                            meta.isPrivate = 'No';
                        }
                    }
                }

                if (meta.bio === 'Nincs bio') {
                    const bioMatch = data.match(/"biography":"([^"]+)"/);
                    if (bioMatch) {
                        meta.bio = bioMatch[1].replace(/\\n/g, ' ').replace(/\\u[0-9a-fA-F]{4}/g, '');
                    }
                }

                if (meta.isPrivate === 'Unknown') {
                    if (data.includes('"is_private":true')) {
                        meta.isPrivate = 'Yes';
                    } else if (data.includes('"is_private":false')) {
                        meta.isPrivate = 'No';
                    }
                }

                event.reply('instagram-osint-res', {
                    success: true,
                    stats: {
                        followers: meta.followers,
                        following: meta.following,
                        posts: meta.posts,
                        isPrivate: meta.isPrivate
                    },
                    user: {
                        bio: meta.bio,
                        fullName: meta.fullName
                    },
                    username: username
                });
            } catch (e) {
                event.reply('instagram-osint-res', {
                    success: false,
                    msg: 'Instagram parsing error: ' + e.message
                });
            }
        });
    }).on('error', (e) => {
        event.reply('instagram-osint-res', {
            success: false,
            msg: 'Instagram request failed: ' + e.message
        });
    });
});

